INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (75, 'com.laiketui.userapi.service.AddressService', 'mapping', 'laike-user', 'e2b5760ab3a2a90d6b4f64174d4a42b0', '2023-03-21 06:52:38', '2023-03-21 06:52:38', NULL, '192.168.0.9', '', '', NULL, NULL, NULL, 'text', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (98, 'thinkinshop.yml', 'DEFAULT_GROUP', 'node.wx-certp12-path=/var/pay\nuploadFile=/usr/local/imgs', 'ab8373008db95dc04cd79c9ceab53736', '2023-03-21 08:40:09', '2023-03-21 08:50:14', 'nacos', '0:0:0:0:0:0:0:1', '', '', '', '', '', 'text', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (102, 'laike-app.yaml', 'DEFAULT_GROUP', 'app:\n    title: 来客推电商\n    store_id: 1', 'a17edd17e8091fff1eba508c07b30008', '2023-03-21 09:06:15', '2023-03-21 09:06:15', NULL, '0:0:0:0:0:0:0:1', '', '', NULL, NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (126, 'common.yml', 'DEFAULT_GROUP', 'spring:\n  messages:\n    fallbackToSystemLocale: false\n    basename: i18n/tips\n    encoding: UTF-8\n  flyway:\n    enabled: false\n  jmx:\n    enabled: false\n  http:\n    encoding:\n      force: true\n      charset: UTF-8\n      enabled: true\n  servlet:\n    multipart:\n      max-file-size: 10MB\n      max-request-size: 30MB\n      file-size-threshold: 1\n  redis:\n    host: ${REDIS_HOST:localhost}\n    port: ${REDIS_PORT:6339}\n    password: ${REDIS_PWD:laiketui18}\n    lettuce:\n      pool:\n        # 连接池中的最大空闲连接 默认8\n        max-idle: 100\n        # 连接池中的最小空闲连接 默认0\n        min-idle: 0\n        # 连接池最大连接数 默认8 ，负数表示没有限制\n        max-active: 20\n        # 连接池最大阻塞等待时间（使用负值表示没有限制） 默认-1\n        max-wait: -1\n    timeout: 30000\n    database: ${REDIS_DB:0}\n  datasource:\n    driver-class-name: com.mysql.cj.jdbc.Driver\n    url: jdbc:mysql://${DB_HOST:192.168.0.48}:${DB_PORT:3306}/${DB_NAME:v3_new_db}?useUnicode=true&autoReconnect=true&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n    username: ${DB_USER:root}\n    password: ${DB_PWD:root}\n    type: com.alibaba.druid.pool.DruidDataSource\n    initialSize: 1\n    minIdle: 1\n    maxIdle: 5\n    maxActive: 20\n    maxWait: 60000\n    timeBetweenEvictionRunsMillis: 60000\n    minEvictableIdleTimeMillis: 300000\n    validationQuery: SELECT 1 FROM DUAL\n    testWhileIdle: true\n    testOnBorrow: false\n    testOnReturn: false\n    poolPreparedStatements: true\n    filters: stat,wall\n    maxPoolPreparedStatementPerConnectionSize: 20\n    connectionProperties: druid.stat.mergeSql=true;druid.stat.slowSqlMillis=5000\n    druid:\n      stat-view-servlet:\n        enabled: true\n        url-pattern: /druid/*\n        reset-enable: true\n        login-username: admin\n        login-password: admin123\n        allow: 127.0.0.1\n\npush:\n  #是否开启 true开启 false 关闭 test\n  status: true\n  appid: nJaIsWP1Zt5g5XCapMDgs5\n  appkey: xgfKQIWvMo7Q0FqrKVMvr3\n  mastersecret: QSqJyNRI596TaL0AkbxIx1\n  host: http://sdk.open.api.igexin.com/apiex.htm\n  #收到消息是否立即启动应用：1为立即启动，2则广播等待客户端自启动\n  transmissiontype: 1\n\n\nuploadFile:\n  path: ${UPLOAD_PATH:/usr/local/imgs}\n\ndubbo:\n  reference:\n    generic: true\n\nelasticSearch:\n  hostlist: 47.107.123.240:19200\n  client:\n    connectNum: 10\n    connectPerRoute: 3\n\n\n', 'c4cc32aee5fc6f0fcdaf76ecbcae7f34', '2023-03-23 11:12:18', '2023-06-16 01:36:37', 'nacos', '127.0.0.1', '', '', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (127, 'laike-user-dev.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: ${tomcat_port:18001}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /user\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 127.0.0.1\n\n# Nacos 注册中心\n# dubbo:\n#   application:\n#     name: laike-user\n#     # 禁用QOS同一台机器可能会有端口冲突现象\n#     qos-enable: false\n#     qos-accept-foreign-ip: false\n#     # 配置注册中心\n#   registry:\n#     address: nacos://localhost:8848\n#   # 设置超时时间\n#   consumer:\n#     timeout: 6000\n#   protocol:\n#     name: dubbo\n#     port: ${NACOS_PORT:21889} \n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-user\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21889} \n\n#swagger 配置\nswagger:\n  title: 来客电商-用户接口\n  desc: 来客电商用户接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.user\n  groupName: 用户\n  contactName: user\n  contactUrl: http://www.laiketui.com/\n  contactEmail:', '4a0bfdc62eff473744e3d3f0185627c0', '2023-03-23 11:15:25', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', '', 'da8f7d37-960a-4c94-9691-9c77711d995c', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (129, 'laike-user-local.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: ${tomcat_port:18002}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /user\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 127.0.0.1\n\n# Nacos 注册中心\n# dubbo:\n#   application:\n#     name: laike-user\n#     # 禁用QOS同一台机器可能会有端口冲突现象\n#     qos-enable: false\n#     qos-accept-foreign-ip: false\n#     # 配置注册中心\n#   registry:\n#     address: nacos://localhost:8848\n#   # 设置超时时间\n#   consumer:\n#     timeout: 6000\n#   protocol:\n#     name: dubbo\n#     port: ${NACOS_PORT:21889} \n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-user\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://47.107.123.240:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21889} \n\n#swagger 配置\nswagger:\n  title: 来客电商-用户接口\n  desc: 来客电商用户接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.user\n  groupName: 用户\n  contactName: user\n  contactUrl: http://www.laiketui.com/\n  contactEmail:', '0eaae5d62b06402c3a98e5c0d24bd1e5', '2023-03-23 11:16:46', '2024-01-15 08:31:13', 'nacos', '127.0.0.1', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (136, 'dubbo-user', 'DEFAULT_GROUP', '# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-user\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21889}', '0d9b848787a61b27c2fcb87149761b64', '2023-03-23 11:45:56', '2023-03-23 11:45:56', NULL, '0:0:0:0:0:0:0:1', '', '0d520842-2b37-4467-ab8f-6c52cbf3374a', NULL, NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (170, 'comm-dev.yml', 'DEFAULT_GROUP', 'spring:\n  cloud:\n    nacos: \n      discovery:\n        ip: localhost\n    sentinel:\n      transport:\n        dashboard: 127.0.0.1:9527\n        port: 8719\n      eager: true\n  redis:\n    host: localhost\n    port: 6339\n    password: laiketui18\n    lettuce:\n      pool:\n        # 连接池中的最大空闲连接 默认8\n        max-idle: 100\n        # 连接池中的最小空闲连接 默认0\n        min-idle: 0\n        # 连接池最大连接数 默认8 ，负数表示没有限制\n        max-active: 20\n        # 连接池最大阻塞等待时间（使用负值表示没有限制） 默认-1\n        max-wait: -1\n    timeout: 30000\n    database: 6\n  # =======================shardingsphere 读写分离先搭建好主从库，再到这边配置 =============================\n  shardingsphere:\n    # 是否开启SQL显示\n    # props:\n    #   sql:\n    #     show: true \n    datasource:\n      # names: lkt-ds-master-0,ds-slave-0-1\n      names: lkt-ds-master-0\n      #主库-写库 \n      # lkt-ds-master-0:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3307/java_main_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root\n      #主库-从库-读库 可多个从库 这里主从都是用的同一个库\n      # ds-slave-0-1:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3308/java_main_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root \n      #主库-写库\n      lkt-ds-master-0: \n        # url: jdbc:mysql://47.107.123.240:3306/v3_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        # username: root\n        # password: 51bbec4bcde2ef40\n        # url: jdbc:mysql://192.168.0.48:3306/v3_24db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        # username: root\n        # password: root\n        # &amp;allowMultiQueries=true&amp;rewriteBatchedStatements=true&amp;failOverReadOnly=false&amp;serverTimezone=UTC\n        # url: jdbc:mysql://47.107.123.240:3316/v3_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        # url: jdbc:mysql://localhost:3306/v3_new_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        url: jdbc:mysql://localhost:3316/v3_test_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&rewriteBatchedStatements=true&connectTimeout=300000&socketTimeout=600000\n        username: root\n        password: 123456\n        # password: 51bbec4bcde2ef40\n        type: com.alibaba.druid.pool.DruidDataSource\n        # type: com.zaxxer.hikari.HikariDataSource\n        driver-class-name: com.mysql.cj.jdbc.Driver \n        initial-size: 10\n        min-idle: 2\n        maxActive: 10\n        # 配置获取连接等待超时的时间\n        maxWait: 60000\n        # 配置间隔多久才进行一次检测，检测需要关闭的空闲连接，单位是毫秒\n        timeBetweenEvictionRunsMillis: 6000\n        # 配置一个连接在池中最小生存的时间，单位是毫秒\n        minEvictableIdleTimeMillis: 30000\n        minEvictableEvictionTimeMillis: 6000000\n        validationQuery: select 1\n        testWhileIdle: true\n        testOnBorrow: false\n        testOnReturn: false\n        # 打开PSCache，并且指定每个连接上PSCache的大小\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        # 配置监控统计拦截的filters，去掉后监控界面sql无法统计，\'wall\'用于防火墙\n        filters: stat,wall,slf4j\n        # 通过connectProperties属性来打开mergeSql功能；慢SQL记录\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=50000\n        wall:\n          multi-statement-allow: true\n      #主库-从库-读库 可多个从库 这里主从都是用的同一个库\n      # ds-slave-0-1:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3308/java_main_db?useUnicode=true&autoReconnect=true&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root \n      #   testWhileIdle: true\n    # 读写分离配置，需要的时候打开这个注释\n    #masterslave:\n    #  name: lkt-ms\n    #  load-balance-algorithm-type: round_robin\n    #  master-data-source-name: lkt-ds-master-0\n    #  slave-data-source-names: ds-slave-0-1\n\n  flyway:\n    enabled: false\n  jmx:\n    enabled: false\n  http:\n    encoding:\n      force: true\n      charset: UTF-8\n      enabled: true\n  servlet:\n    multipart:\n      max-file-size: 500MB\n      max-request-size: 500MB\n      file-size-threshold: 1\n  messages:\n   fallbackToSystemLocale: false\n   basename: i18n/tips\n   encoding: UTF-8\n\n#文件上传路径\nuploadFile:\n  path: /usr/local/imgs/\n\n#日志级别\nlogging:\n  config: classpath:logback-spring.xml\n  level:\n    com:\n      laiketui: info\n      \n##集群用\",\"连接\n# elasticSearch:\n#   hostlist: 47.107.123.240:19200\n#   client:\n#     connectNum: 10\n#     connectPerRoute: 3\n\nlkt-gateway:\n  # SQL敏感字正则\n  regx: sleep|select|insert|into|update|delete|from|where|and|or|trancate|drop|execute|like|grant|use|union|by\n  # 单个IP每分钟请求次数上线\n  request_limit_perip:\n    limit: 1500000\n    # 默认是一分钟：60秒\n    time: 60\n\n  #black ip 黑名单 禁止访问 \n  blacklist:\n    ips: 192.168.0.222\n\nfeign:\n  hystrix:\n    enabled: false\n    \nribbon:\n  ReadTimeout: 10000\n  ConnectTimeout: 10000\n    \n# seata配置\nseata:\n  enabled: true\n  # Seata 应用编号，默认为 ${spring.application.name}\n  application-id: ${spring.application.name}\n  # Seata 事务组编号，用于 TC 集群名\n  tx-service-group: mygroup\n  # 关闭自动代理\n  # enable-auto-data-source-proxy: false\n  enableAutoDataSourceProxy: false\n  # use-jdk-proxy: true\n  # 服务配置项\n  service:\n    # 虚拟组和分组的映射\n    vgroup-mapping:\n      mygroup: default\n    # seeata 所在服务器的端口要打开 8091 \n    # grouplist:\n    #   default: 1.2.3.4:8091\n  # config:\n  #   type: nacos\n  #   nacos:\n  #     server-addr: 47.107.123.240:8848\n  #     namespace: da8f7d37-960a-4c94-9691-9c77711d995c\n  #     # 这是默认值\n  #     data-id: seataServer-dev.properties\n  #     # 这是默认值\n  #     group: DEFAULT_GROUP\n\n  # registry:\n  #   type: nacos\n  #   nacos:\n  #     server-addr: 47.107.123.240:8848\n  #     namespace: da8f7d37-960a-4c94-9691-9c77711d995c \n  #     #默认值和 config 的 SEATA_GROUP 不一样 \n  #     group: DEFAULT_GROUP ', '29da9167f2b31e820a99e93fc0266b60', '2023-03-28 02:35:13', '2024-11-28 03:42:08', 'nacos', '0:0:0:0:0:0:0:1', '', 'da8f7d37-960a-4c94-9691-9c77711d995c', '各个环境都一样的配置', '', '', 'yaml', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (180, 'comm-demo.yml', 'DEFAULT_GROUP', 'spring:\n  cloud:\n    nacos: \n      discovery:\n        ip: localhost\n    sentinel:\n      transport:\n        dashboard: 127.0.0.1:9527\n        port: 8719\n      eager: true\n  redis:\n    host: localhost\n    port: 6339\n    password: laiketui18\n    lettuce:\n      pool:\n        # 连接池中的最大空闲连接 默认8\n        max-idle: 100\n        # 连接池中的最小空闲连接 默认0\n        min-idle: 0\n        # 连接池最大连接数 默认8 ，负数表示没有限制\n        max-active: 20\n        # 连接池最大阻塞等待时间（使用负值表示没有限制） 默认-1\n        max-wait: -1\n    timeout: 30000\n    database: 5\n  # =======================shardingsphere 读写分离先搭建好主从库，再到这边配置 =============================\n  shardingsphere:\n    # 是否开启SQL显示\n    # props:\n    #   sql:\n    #     show: true \n    datasource:\n      # names: lkt-ds-master-0,ds-slave-0-1\n      names: lkt-ds-master-0\n      #主库-写库 \n      # lkt-ds-master-0:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3307/java_main_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root\n      #主库-从库-读库 可多个从库 这里主从都是用的同一个库\n      # ds-slave-0-1:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3308/java_main_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root \n      #主库-写库\n      lkt-ds-master-0: \n        # url: jdbc:mysql://47.107.123.240:3306/v3_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        # username: root\n        # password: 51bbec4bcde2ef40\n        # url: jdbc:mysql://192.168.0.48:3306/v3_24db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        # username: root\n        # password: root\n        # &amp;allowMultiQueries=true&amp;rewriteBatchedStatements=true&amp;failOverReadOnly=false&amp;serverTimezone=UTC\n        # url: jdbc:mysql://47.107.123.240:3316/v3_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        # url: jdbc:mysql://localhost:3306/v3_new_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        url: jdbc:mysql://localhost:3316/v3_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&rewriteBatchedStatements=true&connectTimeout=300000&socketTimeout=600000\n        username: root\n        password: 123456\n        # password: 51bbec4bcde2ef40\n        type: com.alibaba.druid.pool.DruidDataSource\n        # type: com.zaxxer.hikari.HikariDataSource\n        driver-class-name: com.mysql.cj.jdbc.Driver \n        initial-size: 10\n        min-idle: 2\n        maxActive: 10\n        # 配置获取连接等待超时的时间\n        maxWait: 60000\n        # 配置间隔多久才进行一次检测，检测需要关闭的空闲连接，单位是毫秒\n        timeBetweenEvictionRunsMillis: 6000\n        # 配置一个连接在池中最小生存的时间，单位是毫秒\n        minEvictableIdleTimeMillis: 30000\n        minEvictableEvictionTimeMillis: 6000000\n        validationQuery: select 1\n        testWhileIdle: true\n        testOnBorrow: false\n        testOnReturn: false\n        # 打开PSCache，并且指定每个连接上PSCache的大小\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        # 配置监控统计拦截的filters，去掉后监控界面sql无法统计，\'wall\'用于防火墙\n        filters: stat,wall,slf4j\n        # 通过connectProperties属性来打开mergeSql功能；慢SQL记录\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=50000\n        wall:\n          multi-statement-allow: true\n      #主库-从库-读库 可多个从库 这里主从都是用的同一个库\n      # ds-slave-0-1:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3308/java_main_db?useUnicode=true&autoReconnect=true&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root \n      #   testWhileIdle: true\n    # 读写分离配置，需要的时候打开这个注释\n    #masterslave:\n    #  name: lkt-ms\n    #  load-balance-algorithm-type: round_robin\n    #  master-data-source-name: lkt-ds-master-0\n    #  slave-data-source-names: ds-slave-0-1\n\n  flyway:\n    enabled: false\n  jmx:\n    enabled: false\n  http:\n    encoding:\n      force: true\n      charset: UTF-8\n      enabled: true\n  servlet:\n    multipart:\n      max-file-size: 500MB\n      max-request-size: 500MB\n      file-size-threshold: 1\n  messages:\n   fallbackToSystemLocale: false\n   basename: i18n/tips\n   encoding: UTF-8\n\n#文件上传路径\nuploadFile:\n  path: /usr/local/imgs/\n\n#日志级别\nlogging:\n  config: classpath:logback-spring.xml\n  level:\n    com:\n      laiketui: info\n      \n##集群用\",\"连接\n# elasticSearch:\n#   hostlist: 47.107.123.240:19200\n#   client:\n#     connectNum: 10\n#     connectPerRoute: 3\n\nlkt-gateway:\n  # 单个IP每分钟请求次数上线\n  request_limit_perip:\n    limit: 150\n    # 默认是一分钟：60秒\n    time: 60\n\n  #black ip 黑名单 禁止访问 \n  blacklist:\n    ips: 192.168.0.222\n\nfeign:\n  hystrix:\n    enabled: false\n    \nribbon:\n  ReadTimeout: 10000\n  ConnectTimeout: 10000\n    \n# seata配置\nseata:\n  enabled: true\n  # Seata 应用编号，默认为 ${spring.application.name}\n  application-id: ${spring.application.name}\n  # Seata 事务组编号，用于 TC 集群名\n  tx-service-group: mygroup\n  # 关闭自动代理\n  # enable-auto-data-source-proxy: false\n  enableAutoDataSourceProxy: false\n  # use-jdk-proxy: true\n  # 服务配置项\n  service:\n    # 虚拟组和分组的映射\n    vgroup-mapping:\n      mygroup: default\n    # seeata 所在服务器的端口要打开 8091 \n    # grouplist:\n    #   default: 1.2.3.4:8091\n  # config:\n  #   type: nacos\n  #   nacos:\n  #     server-addr: 47.107.123.240:8848\n  #     namespace: da8f7d37-960a-4c94-9691-9c77711d995c\n  #     # 这是默认值\n  #     data-id: seataServer-dev.properties\n  #     # 这是默认值\n  #     group: DEFAULT_GROUP\n\n  # registry:\n  #   type: nacos\n  #   nacos:\n  #     server-addr: 47.107.123.240:8848\n  #     namespace: da8f7d37-960a-4c94-9691-9c77711d995c \n  #     #默认值和 config 的 SEATA_GROUP 不一样 \n  #     group: DEFAULT_GROUP ', '12fb63bac161b29b38dfe27f0b4ba8d6', '2023-03-28 03:59:50', '2024-08-26 06:17:35', 'nacos', '127.0.0.1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', '各个环境都一样的配置', '', '', 'yaml', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (186, 'laike-user-demo.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: ${tomcat_port:18001}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /user\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 127.0.0.1\n\n# Nacos 注册中心\n# dubbo:\n#   application:\n#     name: laike-user\n#     # 禁用QOS同一台机器可能会有端口冲突现象\n#     qos-enable: false\n#     qos-accept-foreign-ip: false\n#     # 配置注册中心\n#   registry:\n#     address: nacos://localhost:8848\n#   # 设置超时时间\n#   consumer:\n#     timeout: 6000\n#   protocol:\n#     name: dubbo\n#     port: ${NACOS_PORT:21889} \n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-user\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21889} \n\n#swagger 配置\nswagger:\n  title: 来客电商-用户接口\n  desc: 来客电商用户接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.user\n  groupName: 用户\n  contactName: user\n  contactUrl: http://www.laiketui.com/\n  contactEmail:', '4a0bfdc62eff473744e3d3f0185627c0', '2023-03-28 04:06:22', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (195, 'laike-task-dev.yml', 'DEFAULT_GROUP', 'server:\n  port: ${tomcat_port:18001}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /task\n    \n#dubbo:\n#  application:\n#    name: laike_app\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 21898\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-task\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21898}\n\nlogging:\n  level:\n    com:\n      laiketui: info\n  config: classpath:logback.xml\n#swagger 配置\nswagger:\n  title: 来客电商-任务调度\n  desc: 来客电商任务调度\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.task\n  groupName: 任务调度\n  contactName: task\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n#xxl-job\nxxl:\n  job:\n    accessToken:\n    admin:\n      addresses: http://127.0.0.1:3366/task # 任务调度中心部署根地址（必填）\n    executor:\n      appname: laike-task                   # 对应 执行管理器 AppName\n      ip: 127.0.0.1                         # 执行器ip，可以不填，会自动识别注册\n      logpath: ./task.log                   # 执行器运行日志文件存储磁盘路径\n      logretentiondays: 30                  # 执行器日志保存天数，值大于3时生效，启用执行器log文件定期清理功能，否则不生效。\n      port: 2024                           # 执行器端口号 \n      #AccessToken：执行器通讯token，非空时启用', '85383ede35e56ca104fcc5df1e36ecf4', '2023-03-28 04:13:22', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', '', 'da8f7d37-960a-4c94-9691-9c77711d995c', '定时任务', NULL, NULL, 'yaml', NULL, '');
