INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (297, 'laike-invoice-dev.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: 18001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /invoice\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 0.0.0.0\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-invoice\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21890}\n \n\n#swagger 配置\nswagger:\n  title: 来客电商-发票接口\n  desc: 来客电商发票接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.invoice\n  groupName: 发票\n  contactName: invoice\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n  ', 'a38d0ea46192bc04f0b7269b7da9c814', '2023-03-28 09:34:38', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', '', 'da8f7d37-960a-4c94-9691-9c77711d995c', '发票模块', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (299, 'laike-gateway-dev.yml', 'DEFAULT_GROUP', 'server:\n  port: 18001\n  tomcat:\n    uri-encoding: UTF-8\n  ssl:\n    enabled: false\n    connection-timeout: 20000\n\nspring:\n  main:\n    allow-bean-definition-overriding: true\n  jmx:\n    enabled: false\n  application:\n    name: laike-gateway\n  resources:\n    static-locations: classpath:/static/\n  mvc:\n    static-path-pattern: /gw/images/**\n  servlet:\n    multipart:\n      max-file-size: 10MB\n      max-request-size: 30MB\n      file-size-threshold: 1\n  multipart:\n    # 上传文件的临时目录\n    location: /upload\n  http:\n    encoding:\n      force: true\n      charset: UTF-8\n      enabled: true\n  messages:\n    basenames: i18n/tips\n    encoding: UTF-8\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-gateway\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20888}\n\n', 'f86a3dd251c802dcbd5f3fa8910c2998', '2023-03-28 09:41:42', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', '', 'da8f7d37-960a-4c94-9691-9c77711d995c', '网关模块', NULL, NULL, 'yaml', NULL, '');
