INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (359, 'laike-mch-local.yml', 'DEFAULT_GROUP', 'server:\n  port: ${TOMCAT_PORT:18006}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 对应 tomcat/webapps/mch\n    context-path: /mch\n    \nnode:\n  ip: 127.0.0.1\n\n#dubbo:\n#  application:\n#    name: laike-mch\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: ${ZOOKEEPER_PORT:20992}\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-mch\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://47.107.123.240:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20992}\n\n#swagger 配置\nswagger:\n  title: 来客电商-店铺接口\n  desc: 来客电商店铺接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.mch\n  groupName: 店铺\n  contactName: mch\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n', 'd862d78fb6252279879bb5aca032ca21', '2023-03-28 10:12:33', '2024-01-15 08:38:45', 'nacos', '0:0:0:0:0:0:0:1', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', '移动端店铺模块', '', '', 'yaml', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (360, 'laike-invoice-local.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: ${tomcat_port:18015}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /invoice\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 127.0.0.1\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-invoice\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://47.107.123.240:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21890}\n \n\n#swagger 配置\nswagger:\n  title: 来客电商-发票接口\n  desc: 来客电商发票接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.invoice\n  groupName: 发票\n  contactName: invoice\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n  ', '21ad6211738524284cad098d42cbc6d5', '2023-03-28 10:12:33', '2024-01-15 08:39:37', 'nacos', '0:0:0:0:0:0:0:1', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', '发票模块', '', '', 'yaml', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (361, 'laike-gateway-local.yml', 'DEFAULT_GROUP', 'server:\n  port: ${tomcat_port:18001}\n  tomcat:\n    uri-encoding: UTF-8\n  ssl:\n    enabled: false\n    connection-timeout: 20000\n\nspring:\n  main:\n    allow-bean-definition-overriding: true\n  jmx:\n    enabled: false\n  application:\n    name: laike-gateway\n  resources:\n    static-locations: classpath:/static/\n  mvc:\n    static-path-pattern: /gw/images/**\n  servlet:\n    multipart:\n      max-file-size: 10MB\n      max-request-size: 30MB\n      file-size-threshold: 1\n  multipart:\n    # 上传文件的临时目录\n    location: /upload\n  http:\n    encoding:\n      force: true\n      charset: UTF-8\n      enabled: true\n  messages:\n    basenames: i18n/tips\n    encoding: UTF-8\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-gateway\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://47.107.123.240:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20888}\n\n', 'abe6bc22def534e0c96eb6e2741515d0', '2023-03-28 10:12:33', '2024-01-15 08:40:19', 'nacos', '127.0.0.1', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', '网关模块', '', '', 'yaml', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (362, 'laike-freight-local.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: ${tomcat_port:18014}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /freight\n    \n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 0.0.0.0\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-freight\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://47.107.123.240:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21890}\n\n\n\n#swagger 配置\nswagger:\n  title: 来客电商-运费接口\n  desc: 来客电商运费接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.freight\n  groupName: 运费\n  contactName: freight\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n\n', '0f585927ffc74b9c14ae93598140e712', '2023-03-28 10:12:33', '2024-01-15 08:41:30', 'nacos', '127.0.0.1', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', '运费模块', '', '', 'yaml', '', '');
