g\",\"storeId\":\"int\",\"pageNum\":\"int\",\"accessId\":\"java.lang.String\",\"exportType\":\"java.lang.Integer\",\"pageNo\":\"int\",\"brandId\":\"java.lang.Integer\",\"shopId\":\"int\",\"proName\":\"java.lang.String\",\"page\":\"int\"}},{\"type\":\"org.springframework.web.multipart.MultipartFile\"},{\"type\":\"java.lang.Object\"},{\"type\":\"java.lang.String\"},{\"type\":\"com.laiketui.domain.vo.mch.SetShopVo\",\"properties\":{\"posterImg\":\"java.lang.String\",\"storeType\":\"int\",\"address\":\"java.lang.String\",\"shopInformation\":\"java.lang.String\",\"isInvoice\":\"java.lang.Integer\",\"headImg\":\"java.lang.String\",\"cityAll\":\"java.lang.String\",\"businessHours\":\"java.lang.String\",\"pageSize\":\"int\",\"language\":\"java.lang.String\",\"idNumber\":\"java.lang.String\",\"storeId\":\"int\",\"pageNum\":\"int\",\"realname\":\"java.lang.String\",\"accessId\":\"java.lang.String\",\"isOpen\":\"java.lang.String\",\"file\":\"org.springframework.web.multipart.MultipartFile\",\"exportType\":\"java.lang.Integer\",\"pageNo\":\"int\",\"name\":\"java.lang.String\",\"tel\":\"java.lang.String\",\"shopId\":\"int\",\"shopRange\":\"java.lang.String\",\"cid\":\"java.lang.Integer\"}}],\"annotations\":[]}', 'abdee3a9ef8230424907ca34ae3c1844', '2023-11-10 09:48:43', '2024-07-29 08:45:00', NULL, '192.168.2.49', '', '', NULL, NULL, NULL, 'text', NULL, '');
