INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1253, 'nacos.cfg.dataIdfoo', 'foo', 'helloWorld', '1a833da63a6b7e20098dae06d06602e1', '2023-11-20 15:52:23', '2025-04-08 05:17:36', NULL, '185.254.30.30', '', '', NULL, NULL, NULL, 'text', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1279, 'laike-plugin-seckill-dev.yml', 'DEFAULT_GROUP', 'server:\n  port: 19001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /seckill\n    \nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-seckill\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20904}\n\n\n#swagger 配置\nswagger:\n  title: 来客电商-秒杀接口\n  desc: 来客电商秒杀接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.seckill\n  groupName: 秒杀\n  contactName: seckill\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com', '57c821c75b54923eb85c69595004dc20', '2024-01-15 07:36:00', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', '', 'da8f7d37-960a-4c94-9691-9c77711d995c', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1282, 'laike-plugin-presell-dev.yml', 'DEFAULT_GROUP', 'server:\n  port: :19001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /presell\n\nnode:\n  ip: 0.0.0.0\n\n#dubbo:\n#  application:\n#    name: laike-presell\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 21924\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-plugin-presell\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21924}\n  \n\n#swagger 配置\nswagger:\n  title: 来客电商-预售接口\n  desc: 来客电商预售接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.presell\n  groupName: 预售\n  contactName: presell\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com', '8248c58284c18efe38298d67a9d11aa8', '2024-01-15 07:37:33', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', '', 'da8f7d37-960a-4c94-9691-9c77711d995c', 'java主线预售', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1295, 'laike-plugin-diy-dev.yml', 'DEFAULT_GROUP', 'server:\n  port: 19001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /diy\n    \nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-diy\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20904}\n\n#swagger 配置\nswagger:\n  title: 来客电商-diy模板接口\n  desc: 来客电商diy模板接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.diy\n  groupName: diy模板\n  contactName: diy\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com\n', '3a3d428f69d7eb699689d4d7bc73a13e', '2024-01-15 07:45:49', '2024-01-26 01:43:10', NULL, '0:0:0:0:0:0:0:1', '', 'da8f7d37-960a-4c94-9691-9c77711d995c', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1304, 'comm-local.yml', 'DEFAULT_GROUP', 'spring:\n  cloud:\n    nacos: \n      discovery:\n        ip: localhost\n    # sentinel:\n    #   transport:\n    #     dashboard: 127.0.0.1:9527\n    #     port: 8719\n    #   eager: true\n  redis:\n    host: localhost\n    port: 6339\n    password: laiketui18\n    lettuce:\n      pool:\n        # 连接池中的最大空闲连接 默认8\n        max-idle: 100\n        # 连接池中的最小空闲连接 默认0\n        min-idle: 0\n        # 连接池最大连接数 默认8 ，负数表示没有限制\n        max-active: 20\n        # 连接池最大阻塞等待时间（使用负值表示没有限制） 默认-1\n        max-wait: -1\n    timeout: 30000\n    database: 14\n  # =======================shardingsphere 读写分离先搭建好主从库，再到这边配置 =============================\n  shardingsphere:\n    # 是否开启SQL显示\n    # props:\n    #   sql:\n    #     show: true \n    datasource:\n      # names: lkt-ds-master-0,ds-slave-0-1\n      names: lkt-ds-master-0\n      #主库-写库 \n      # lkt-ds-master-0:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3307/java_main_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root\n      #主库-从库-读库 可多个从库 这里主从都是用的同一个库\n      # ds-slave-0-1:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3308/java_main_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root \n      #主库-写库\n      lkt-ds-master-0: \n        # url: jdbc:mysql://47.107.123.240:3306/v3_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        # username: root\n        # password: 51bbec4bcde2ef40\n        # url: jdbc:mysql://112.74.34.238:3316/v3_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        # username: root\n        # password: root\n        # &amp;allowMultiQueries=true&amp;rewriteBatchedStatements=true&amp;failOverReadOnly=false&amp;serverTimezone=UTC\n        # url: jdbc:mysql://47.107.123.240:3316/v3_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        # url: jdbc:mysql://localhost:3306/v3_new_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        url: jdbc:mysql://localhost:3306/db_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&rewriteBatchedStatements=true&connectTimeout=300000&socketTimeout=600000\n        username: root\n        password: 123456\n        # password: root\n        type: com.alibaba.druid.pool.DruidDataSource\n        # type: com.zaxxer.hikari.HikariDataSource\n        driver-class-name: com.mysql.cj.jdbc.Driver \n        initial-size: 10\n        min-idle: 2\n        maxActive: 10\n        # 配置获取连接等待超时的时间\n        maxWait: 60000\n        # 配置间隔多久才进行一次检测，检测需要关闭的空闲连接，单位是毫秒\n        timeBetweenEvictionRunsMillis: 6000\n        # 配置一个连接在池中最小生存的时间，单位是毫秒\n        minEvictableIdleTimeMillis: 30000\n        minEvictableEvictionTimeMillis: 6000000\n        validationQuery: select 1\n        testWhileIdle: true\n        testOnBorrow: false\n        testOnReturn: false\n        # 打开PSCache，并且指定每个连接上PSCache的大小\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        # 配置监控统计拦截的filters，去掉后监控界面sql无法统计，\'wall\'用于防火墙\n        filters: stat,wall,slf4j\n        # 通过connectProperties属性来打开mergeSql功能；慢SQL记录\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=50000\n        wall:\n          multi-statement-allow: true\n      #主库-从库-读库 可多个从库 这里主从都是用的同一个库\n      # ds-slave-0-1:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3308/java_main_db?useUnicode=true&autoReconnect=true&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root \n      #   testWhileIdle: true\n    # 读写分离配置，需要的时候打开这个注释\n    #masterslave:\n    #  name: lkt-ms\n    #  load-balance-algorithm-type: round_robin\n    #  master-data-source-name: lkt-ds-master-0\n    #  slave-data-source-names: ds-slave-0-1\n\n  flyway:\n    enabled: false\n  jmx:\n    enabled: false\n  http:\n    encoding:\n      force: true\n      charset: UTF-8\n      enabled: true\n  servlet:\n    multipart:\n      max-file-size: 500MB\n      max-request-size: 500MB\n      file-size-threshold: 1\n  messages:\n   fallbackToSystemLocale: false\n   basename: i18n/tips\n   encoding: UTF-8\n\n#文件上传路径\nuploadFile:\n  path: /usr/local/imgs/\n\n#日志级别\nlogging:\n  config: classpath:logback-spring.xml\n  level:\n    com:\n      laiketui: info\n      \n##集群用\",\"连接\n# elasticSearch:\n#   hostlist: 47.107.123.240:19200\n#   client:\n#     connectNum: 10\n#     connectPerRoute: 3\n\nlkt-gateway:\n  # SQL敏感字正则\n  regx: sleep|select|insert|into|update|delete|from|where|and|or|trancate|drop|execute|grant|use|union|by\n  # 单个IP每分钟请求次数上线\n  request_limit_perip:\n    limit: 15000\n    # 默认是一分钟：60秒\n    time: 60\n\n  #black ip 黑名单 禁止访问 \n  blacklist:\n    ips: 192.168.0.222\n\nfeign:\n  hystrix:\n    enabled: false\n    \nribbon:\n  ReadTimeout: 10000\n  ConnectTimeout: 10000\n    \n# seata配置\nseata:\n  enabled: true\n  # Seata 应用编号，默认为 ${spring.application.name}\n  application-id: ${spring.application.name}\n  # Seata 事务组编号，用于 TC 集群名\n  tx-service-group: mygroup\n  # 关闭自动代理\n  # enable-auto-data-source-proxy: false\n  enableAutoDataSourceProxy: false\n  # use-jdk-proxy: true\n  # 服务配置项\n  service:\n    # 虚拟组和分组的映射\n    vgroup-mapping:\n      mygroup: default\n    # seeata 所在服务器的端口要打开 8091 \n    # grouplist:\n    #   default: 1.2.3.4:8091\n  # config:\n  #   type: nacos\n  #   nacos:\n  #     server-addr: 47.107.123.240:8848\n  #     namespace: da8f7d37-960a-4c94-9691-9c77711d995c\n  #     # 这是默认值\n  #     data-id: seataServer-dev.properties\n  #     # 这是默认值\n  #     group: DEFAULT_GROUP\n\n  # registry:\n  #   type: nacos\n  #   nacos:\n  #     server-addr: 47.107.123.240:8848\n  #     namespace: da8f7d37-960a-4c94-9691-9c77711d995c \n  #     #默认值和 config 的 SEATA_GROUP 不一样 \n  #     group: DEFAULT_GROUP ', '359b63d6c8fc1e43ea17c8b8f9101e1c', '2024-01-15 08:27:44', '2025-04-03 01:11:32', 'nacos', '0:0:0:0:0:0:0:1', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', '各个环境都一样的配置', '', '', 'yaml', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1305, 'seataServer-local.properties', 'DEFAULT_GROUP', '#For details about configuration items, see https://seata.io/zh-cn/docs/user/configurations.html\n#Transport configuration, for client and server\ntransport.type=TCP\ntransport.server=NIO\ntransport.heartbeat=true\ntransport.enableTmClientBatchSendRequest=false\ntransport.enableRmClientBatchSendRequest=true\ntransport.enableTcServerBatchSendResponse=false\ntransport.rpcRmRequestTimeout=30000\ntransport.rpcTmRequestTimeout=30000\ntransport.rpcTcRequestTimeout=30000\ntransport.threadFactory.bossThreadPrefix=NettyBoss\ntransport.threadFactory.workerThreadPrefix=NettyServerNIOWorker\ntransport.threadFactory.serverExecutorThreadPrefix=NettyServerBizHandler\ntransport.threadFactory.shareBossWorker=false\ntransport.threadFactory.clientSelectorThreadPrefix=NettyClientSelector\ntransport.threadFactory.clientSelectorThreadSize=1\ntransport.threadFactory.clientWorkerThreadPrefix=NettyClientWorkerThread\ntransport.threadFactory.bossThreadSize=1\ntransport.threadFactory.workerThreadSize=default\ntransport.shutdown.wait=3\ntransport.serialization=seata\ntransport.compressor=none\n\n#Transaction routing rules configuration, only for the client\n# 此处的mygroup名字可以自定义，只修改这个值即可\nservice.vgroupMapping.mygroup=default\n#If you use a registry, you can ignore it\n#service.default.grouplist=127.0.0.1:8091\n#service.enableDegrade=false\n#service.disableGlobalTransaction=false\n\n#Transaction rule configuration, only for the client\nclient.rm.asyncCommitBufferLimit=10000\nclient.rm.lock.retryInterval=10\nclient.rm.lock.retryTimes=30\nclient.rm.lock.retryPolicyBranchRollbackOnConflict=true\nclient.rm.reportRetryCount=5\nclient.rm.tableMetaCheckEnable=true\nclient.rm.tableMetaCheckerInterval=60000\nclient.rm.sqlParserType=druid\nclient.rm.reportSuccessEnable=false\nclient.rm.sagaBranchRegisterEnable=false\nclient.rm.sagaJsonParser=fastjson\nclient.rm.tccActionInterceptorOrder=-2147482648\nclient.tm.commitRetryCount=5\nclient.tm.rollbackRetryCount=5\nclient.tm.defaultGlobalTransactionTimeout=60000\nclient.tm.degradeCheck=false\nclient.tm.degradeCheckAllowTimes=10\nclient.tm.degradeCheckPeriod=2000\nclient.tm.interceptorOrder=-2147482648\nclient.undo.dataValidation=true\nclient.undo.logSerialization=jackson\nclient.undo.onlyCareUpdateColumns=true\nserver.undo.logSaveDays=7\nserver.undo.logDeletePeriod=86400000\nclient.undo.logTable=undo_log\nclient.undo.compress.enable=true\nclient.undo.compress.type=zip\nclient.undo.compress.threshold=64k\n#For TCC transaction mode\ntcc.fence.logTableName=tcc_fence_log\ntcc.fence.cleanPeriod=1h\n\n#Log rule configuration, for client and server\nlog.exceptionRate=100\n\n#Transaction storage configuration, only for the server. The file, db, and redis configuration values are optional.\n# 默认为file，一定要改为db，我们自己的服务启动会连接不到seata\nstore.mode=db\nstore.lock.mode=db\nstore.session.mode=db\n#Used for password encryption\n\n#These configurations are required if the `store mode` is `db`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `db`, you can remove the configuration block.\n# 修改mysql的配置\nstore.db.datasource=druid\nstore.db.dbType=mysql\nstore.db.driverClassName=com.mysql.cj.jdbc.Driver\n# 指定seata的数据库，下面会提\nstore.db.url=jdbc:mysql://192.168.0.48:3306/seata?useUnicode=true&rewriteBatchedStatements=true\nstore.db.user=root\nstore.db.password=root\nstore.db.minConn=5\nstore.db.maxConn=30\nstore.db.globalTable=global_table\nstore.db.branchTable=branch_table\nstore.db.distributedLockTable=distributed_lock\nstore.db.queryLimit=100\nstore.db.lockTable=lock_table\nstore.db.maxWait=50000\n\n\n#Transaction rule configuration, only for the server\nserver.recovery.committingRetryPeriod=600000\nserver.recovery.asynCommittingRetryPeriod=600000\nserver.recovery.rollbackingRetryPeriod=600000\nserver.recovery.timeoutRetryPeriod=600000\nserver.maxCommitRetryTimeout=-1\nserver.maxRollbackRetryTimeout=-1\nserver.rollbackRetryTimeoutUnlockEnable=false\nserver.distributedLockExpireTime=600000\nserver.xaerNotaRetryTimeout=600000\nserver.session.branchAsyncQueueSize=50000\nserver.session.enableBranchAsyncRemove=false\nserver.enableParallelRequestHandle=false\n\n#Metrics configuration, only for the server\nmetrics.enabled=false\nmetrics.registryType=compact\nmetrics.exporterList=prometheus\nmetrics.exporterPrometheusPort=9898\n', 'd9bf9aabf967f6f7c5a3470147a51965', '2024-01-15 08:28:22', '2024-01-15 08:28:22', NULL, '127.0.0.1', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', 'seata本地环境', NULL, NULL, 'properties', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1306, 'service.vgroupMapping.mygroup', 'DEFAULT_GROUP', 'default', 'c21f969b5f03d33d43e04f8f136e7682', '2024-01-15 08:28:44', '2024-01-15 08:28:44', NULL, '127.0.0.1', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', '', NULL, NULL, 'text', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1307, 'laike-plugins-mybatis.yml', 'DEFAULT_GROUP', 'mybatis:\n  mapper-locations: classpath:/db/mapping/*Mapper.xml\n  type-aliases-package: com.laiketui.plugin.common.domain.base\n  mapper:\n    identity: MYSQL\n    mappers: tk.mybatis.mapper.commgeneratoron.Mapper\n    not-empty: true\n  ######### 分页插件 ##########\n  pagehelper:\n    helper-dialect: mysql\n    reasonable: true\n    params: count=countSql\n    support-methods-arguments: true', '715d8ab1156e87f5173d70d957af86fb', '2024-01-15 08:29:06', '2024-01-15 08:29:06', NULL, '0:0:0:0:0:0:0:1', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1308, 'laike-base-mybatis.yml', 'DEFAULT_GROUP', 'mybatis:\n  mapper-locations: classpath:/db/mapping/*Mapper.xml\n  type-aliases-package: com.laiketui.domain\n  mapper:\n    identity: MYSQL\n    mappers: tk.mybatis.mapper.commgeneratoron.Mapper\n    not-empty: true\n  ######### 分页插件 ##########\n  pagehelper:\n    helper-dialect: mysql\n    reasonable: true\n    params: count=countSql\n    support-methods-arguments: true', 'f91c71660e4418c7f81bc400f6f448f2', '2024-01-15 08:29:25', '2024-01-15 08:29:25', NULL, '0:0:0:0:0:0:0:1', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1338, 'laike-plugin-group-local.yml', 'DEFAULT_GROUP', 'server:\n  port: ${TOMCAT_PORT:18186}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /group\n    \nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-plugin-group\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://47.107.123.240:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21905}\n\n\n#swagger 配置\nswagger:\n  title: 来客电商-拼团接口\n  desc: 来客电商拼团接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.group\n  groupName: 拼团\n  contactName: group\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com', '7d47c9b5401bdb694c585e7655525a1c', '2024-01-15 08:53:08', '2024-01-15 08:53:49', 'nacos', '127.0.0.1', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', '拼团', '', '', 'yaml', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1340, 'laike-online-message-local.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: ${tomcat_port:18180}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /message\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-online-message\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://47.107.123.240:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21897} \n\n#swagger 配置\nswagger:\n  title: 来客电商-在线聊天\n  desc: 来客电商在线聊天接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.online.message\n  groupName: 在线聊天\n  contactName: message\n  contactUrl: http://www.laiketui.com/\n  contactEmail:', '63b0c51a2b9173dc583d56d090c53cf6', '2024-01-15 08:54:42', '2024-01-15 08:55:18', 'nacos', '0:0:0:0:0:0:0:1', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', 'im服务配置', '', '', 'yaml', '', '');
