_mini_wechat: https://api.mch.weixin.qq.com/v3/pay/transactions/native\n    # Native下单API\n    native_wechat: https://api.mch.weixin.qq.com/v3/pay/transactions/h5\n  certurl:\n    # 服务器证书地址\n    certificatesUrl: https://api.mch.weixin.qq.com/v3/certificates\n  gzh:\n    redirect_uri: https://xiaochengxu.houjiemeishi.com/V3/\n', '37832c8edd475a0656ca408f5d174c14', '2024-01-25 09:17:13', '2024-05-15 10:34:11', 'nacos', '222.244.189.29', '', '23467031-bda4-48a0-a7ab-6bc1a4be22fd', '支付模块', '', '', 'yaml', '', '');
