INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1472, 'laike-online-message-prod.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: 18180\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /message\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-online-message\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21897} \n\n#swagger 配置\nswagger:\n  title: 来客电商-在线聊天\n  desc: 来客电商在线聊天接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.online.message\n  groupName: 在线聊天\n  contactName: message\n  contactUrl: http://www.laiketui.com/\n  contactEmail:', '925acbf4b5506b21f2fa7a7565316607', '2024-01-25 09:17:13', '2024-01-29 11:15:15', 'nacos', '127.0.0.1', '', '23467031-bda4-48a0-a7ab-6bc1a4be22fd', 'im服务配置', '', '', 'yaml', '', '');
