INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1585, 'laike-plugins-mybatis.yml', 'DEFAULT_GROUP', 'mybatis:\n  mapper-locations: classpath:/db/mapping/*Mapper.xml\n  type-aliases-package: com.laiketui.plugin.common.domain.base\n  mapper:\n    identity: MYSQL\n    mappers: tk.mybatis.mapper.commgeneratoron.Mapper\n    not-empty: true\n  ######### 分页插件 ##########\n  pagehelper:\n    helper-dialect: mysql\n    reasonable: true\n    params: count=countSql\n    support-methods-arguments: true', '715d8ab1156e87f5173d70d957af86fb', '2024-01-26 01:44:55', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1586, 'laike-plugin-group-demo.yml', 'DEFAULT_GROUP', 'server:\n  port: 19001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /group\n    \nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-plugin-group\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21905}\n\n\n#swagger 配置\nswagger:\n  title: 来客电商-拼团接口\n  desc: 来客电商拼团接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.group\n  groupName: 拼团\n  contactName: group\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com', '8c00112d3ed0edd636232d36d1446a20', '2024-01-26 01:44:55', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', '拼团', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1587, 'laike-online-message-demo.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: 18180\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /message\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-online-message\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21897} \n\n#swagger 配置\nswagger:\n  title: 来客电商-在线聊天\n  desc: 来客电商在线聊天接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.online.message\n  groupName: 在线聊天\n  contactName: message\n  contactUrl: http://www.laiketui.com/\n  contactEmail:', '925acbf4b5506b21f2fa7a7565316607', '2024-01-26 01:44:55', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', 'im服务配置', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1588, 'seataServer-demo.properties', 'DEFAULT_GROUP', '#For details about configuration items, see https://seata.io/zh-cn/docs/user/configurations.html\n#Transport configuration, for client and server\ntransport.type=TCP\ntransport.server=NIO\ntransport.heartbeat=true\ntransport.enableTmClientBatchSendRequest=false\ntransport.enableRmClientBatchSendRequest=true\ntransport.enableTcServerBatchSendResponse=false\ntransport.rpcRmRequestTimeout=30000\ntransport.rpcTmRequestTimeout=30000\ntransport.rpcTcRequestTimeout=30000\ntransport.threadFactory.bossThreadPrefix=NettyBoss\ntransport.threadFactory.workerThreadPrefix=NettyServerNIOWorker\ntransport.threadFactory.serverExecutorThreadPrefix=NettyServerBizHandler\ntransport.threadFactory.shareBossWorker=false\ntransport.threadFactory.clientSelectorThreadPrefix=NettyClientSelector\ntransport.threadFactory.clientSelectorThreadSize=1\ntransport.threadFactory.clientWorkerThreadPrefix=NettyClientWorkerThread\ntransport.threadFactory.bossThreadSize=1\ntransport.threadFactory.workerThreadSize=default\ntransport.shutdown.wait=3\ntransport.serialization=seata\ntransport.compressor=none\n\n#Transaction routing rules configuration, only for the client\n# 此处的mygroup名字可以自定义，只修改这个值即可\nservice.vgroupMapping.mygroup=default\n#If you use a registry, you can ignore it\n#service.default.grouplist=127.0.0.1:8091\n#service.enableDegrade=false\n#service.disableGlobalTransaction=false\n\n#Transaction rule configuration, only for the client\nclient.rm.asyncCommitBufferLimit=10000\nclient.rm.lock.retryInterval=10\nclient.rm.lock.retryTimes=30\nclient.rm.lock.retryPolicyBranchRollbackOnConflict=true\nclient.rm.reportRetryCount=5\nclient.rm.tableMetaCheckEnable=true\nclient.rm.tableMetaCheckerInterval=60000\nclient.rm.sqlParserType=druid\nclient.rm.reportSuccessEnable=false\nclient.rm.sagaBranchRegisterEnable=false\nclient.rm.sagaJsonParser=fastjson\nclient.rm.tccActionInterceptorOrder=-2147482648\nclient.tm.commitRetryCount=5\nclient.tm.rollbackRetryCount=5\nclient.tm.defaultGlobalTransactionTimeout=60000\nclient.tm.degradeCheck=false\nclient.tm.degradeCheckAllowTimes=10\nclient.tm.degradeCheckPeriod=2000\nclient.tm.interceptorOrder=-2147482648\nclient.undo.dataValidation=true\nclient.undo.logSerialization=jackson\nclient.undo.onlyCareUpdateColumns=true\nserver.undo.logSaveDays=7\nserver.undo.logDeletePeriod=86400000\nclient.undo.logTable=undo_log\nclient.undo.compress.enable=true\nclient.undo.compress.type=zip\nclient.undo.compress.threshold=64k\n#For TCC transaction mode\ntcc.fence.logTableName=tcc_fence_log\ntcc.fence.cleanPeriod=1h\n\n#Log rule configuration, for client and server\nlog.exceptionRate=100\n\n#Transaction storage configuration, only for the server. The file, db, and redis configuration values are optional.\n# 默认为file，一定要改为db，我们自己的服务启动会连接不到seata\nstore.mode=db\nstore.lock.mode=db\nstore.session.mode=db\n#Used for password encryption\n\n#These configurations are required if the `store mode` is `db`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `db`, you can remove the configuration block.\n# 修改mysql的配置\nstore.db.datasource=druid\nstore.db.dbType=mysql\nstore.db.driverClassName=com.mysql.cj.jdbc.Driver\n# 指定seata的数据库，下面会提\nstore.db.url=jdbc:mysql://localhost:3306/seata_db?useUnicode=true&rewriteBatchedStatements=true\nstore.db.user=root\nstore.db.password=51bbec4bcde2ef40\nstore.db.minConn=5\nstore.db.maxConn=30\nstore.db.globalTable=global_table\nstore.db.branchTable=branch_table\nstore.db.distributedLockTable=distributed_lock\nstore.db.queryLimit=100\nstore.db.lockTable=lock_table\nstore.db.maxWait=50000\n\n\n#Transaction rule configuration, only for the server\nserver.recovery.committingRetryPeriod=600000\nserver.recovery.asynCommittingRetryPeriod=600000\nserver.recovery.rollbackingRetryPeriod=600000\nserver.recovery.timeoutRetryPeriod=600000\nserver.maxCommitRetryTimeout=-1\nserver.maxRollbackRetryTimeout=-1\nserver.rollbackRetryTimeoutUnlockEnable=false\nserver.distributedLockExpireTime=600000\nserver.xaerNotaRetryTimeout=600000\nserver.session.branchAsyncQueueSize=50000\nserver.session.enableBranchAsyncRemove=false\nserver.enableParallelRequestHandle=false\n\n#Metrics configuration, only for the server\nmetrics.enabled=false\nmetrics.registryType=compact\nmetrics.exporterList=prometheus\nmetrics.exporterPrometheusPort=9898\n', 'd0de8496fe3c0c53b6e7c33528882417', '2024-01-26 01:44:55', '2024-01-26 07:29:30', NULL, '127.0.0.1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', 'seata本地环境', NULL, NULL, 'properties', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1589, 'laike-seata-demo-demo.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: ${tomcat_port:18018}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /seata-demo\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 127.0.0.1\n\n# Nacos 注册中心\n# dubbo:\n#   application:\n#     name: laike-user\n#     # 禁用QOS同一台机器可能会有端口冲突现象\n#     qos-enable: false\n#     qos-accept-foreign-ip: false\n#     # 配置注册中心\n#   registry:\n#     address: nacos://localhost:8848\n#   # 设置超时时间\n#   consumer:\n#     timeout: 6000\n#   protocol:\n#     name: dubbo\n#     port: ${NACOS_PORT:21889} \n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-seata-demo\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://47.107.123.240:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:22999} \n\n#swagger 配置\nswagger:\n  title: 来客电商-用户接口\n  desc: 来客电商用户接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.user\n  groupName: seata-demo\n  contactName: seata-demo\n  contactUrl: http://www.laiketui.com/\n  contactEmail:', '18ca79ae2027742e472b4c8fbbc026ca', '2024-01-26 01:44:55', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1590, 'service.vgroupMapping.mygroup', 'DEFAULT_GROUP', 'default', 'c21f969b5f03d33d43e04f8f136e7682', '2024-01-26 01:44:55', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', '', NULL, NULL, 'text', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1591, 'laike-plugin-member-demo.yml', 'DEFAULT_GROUP', 'server:\n  port: 19001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /member\n    \nnode:\n  ip: 0.0.0.0\n \n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-plugin-member\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20906}\n\n#swagger 配置\nswagger:\n  title: 来客电商-会员制接口\n  desc: 来客电商会员制接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.member\n  groupName: 会员制\n  contactName: member\n  contactUrl: http://www.member.com/\n  contactEmail: 36309839@qq.com', 'c92fe91241da7a625edba216b61aa6c2', '2024-01-26 01:44:55', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', 'java主线会员制', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1592, 'laike-springcloud-gateway-demo.yml', 'DEFAULT_GROUP', 'server:\n  port: 9526\n  servlet:\n    context-path: /scgw\n    \nspring:\n  cloud:\n    gateway:\n      # 处理跨域请求\n      globalcors:\n        add-to-simple-url-handler-mapping: true\n        cors-configurations:\n          \'[/**]\':\n            allowedHeaders: \"*\"\n            allowedOrigins: \"*\"\n            allowCredentials: true\n            allowedMethods:\n              - GET\n              - POST\n              - DELETE\n              - HEAD\n              - PUT\n              - OPTION \n      default-filters:\n            - DedupeResponseHeader=Vary Access-Control-Allow-Origin Access-Control-Allow-Credentials, RETAIN_FIRST\n\n      routes:\n        # 配置模块路由\n        # PC店铺端接口\n        - id: admin-mch\n          uri: lb://admin-mch\n          predicates:\n            - Path=/admin-mch/**\n#          filters:\n#            - StripPrefix=1\n        # 商城管理后台\n        - id: admin\n          uri: lb://admin\n          predicates:\n            - Path=/admin/**,/saas/**\n        #  filters:\n        #   - StripPrefix=1\n        # 供应商\n        - id: supplier\n          uri: lb://supplier\n          predicates:\n            - Path=/supplier/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端接口\n        - id: app\n          uri: lb://app\n          predicates:\n            - Path=/app/**\n#          filters:\n#            - StripPrefix=1\n        # 优惠券\n        - id: coupon\n          uri: lb://coupon\n          predicates:\n            - Path=/coupon/**\n#          filters:\n#            - StripPrefix=1\n        # 首页DIY\n        - id: diy\n          uri: lb://diy\n          predicates:\n            - Path=/diy/**\n#          filters:\n#            - StripPrefix=1\n        # 资源文件\n        - id: file\n          uri: lb://file\n          predicates:\n            - Path=/file/**\n#          filters:\n#            - StripPrefix=1\n        # 运费\n        - id: freight\n          uri: lb://freight\n          predicates:\n            - Path=/freight/**\n#          filters:\n#            - StripPrefix=1\n        # 网关\n        - id: gateway\n          uri: lb://gateway\n          predicates:\n            - Path=/gw/**\n        # 发票\n        - id: invoice\n          uri: lb://invoice\n          predicates:\n            - Path=/invoice/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端店铺接口\n        - id: mch\n          uri: lb://mch\n          predicates:\n            - Path=/mch/**\n#          filters:\n#            - StripPrefix=1\n        # 会员制\n        - id: member\n          uri: lb://member\n          predicates:\n            - Path=/member/**\n#          filters:\n#            - StripPrefix=1\n        # 订单\n        - id: order\n          uri: lb://order\n          predicates:\n            - Path=/order/**\n#          filters:\n#            - StripPrefix=1\n        # 支付\n        - id: payment\n          uri: lb://payment\n          predicates:\n            - Path=/payment/**\n#          filters:\n#            - StripPrefix=1\n        # 竞拍\n        - id: auction\n          uri: lb://auction\n          predicates:\n            - Path=/auction/**\n#          filters:\n#            - StripPrefix=1\n        # 分销\n        - id: distribute\n          uri: lb://distribute\n          predicates:\n            - Path=/distribute/**\n#          filters:\n#            - StripPrefix=1\n        # 拼团\n        - id: group\n          uri: lb://group\n          predicates:\n            - Path=/group/**\n#          filters:\n#            - StripPrefix=1\n        #\n        - id: integral\n          uri: lb://integral\n          predicates:\n            - Path=/integral/**\n#          filters:\n#            - StripPrefix=1\n        # 签到\n        - id: sign\n          uri: lb://sign\n          predicates:\n            - Path=/sign/**\n#          filters:\n#            - StripPrefix=1\n        # 预售\n        - id: presell\n          uri: lb://presell\n          predicates:\n            - Path=/presell/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端商品\n        - id: products\n          uri: lb://products\n          predicates:\n            - Path=/products/**\n#          filters:\n#            - StripPrefix=1\n        # 秒杀\n        - id: seckill\n          uri: lb://seckill\n          predicates:\n            - Path=/seckill/**\n#          filters:\n#            - StripPrefix=1\n        # PC商城\n        - id: mall\n          uri: lb://mall\n          predicates:\n            - Path=/mall/**\n#          filters:\n#            - StripPrefix=1\n        # 定时任务\n        - id: laike-task\n          uri: lb://laike-task\n          predicates:\n            - Path=/task/**\n#          filters:\n#            - StripPrefix=1\n        # 用户信息\n        - id: user\n          uri: lb://user\n          predicates:\n            - Path=/user/**\n          # filters:\n          #   - StripPrefix=1\n        # seata\n        - id: seata-demo\n          uri: lb://seata-demo\n          predicates:\n            - Path=/seata-demo/**\n          # filters:\n          #   - StripPrefix=1\n    ', 'fea53a70e53f411f036acc724ad28e71', '2024-01-26 01:44:55', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', '网关配置', NULL, NULL, 'text', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1593, 'laike-plugin-seckill-demo.yml', 'DEFAULT_GROUP', 'server:\n  port: 19001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /seckill\n    \nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-seckill\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20904}\n\n\n#swagger 配置\nswagger:\n  title: 来客电商-秒杀接口\n  desc: 来客电商秒杀接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.seckill\n  groupName: 秒杀\n  contactName: seckill\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com', '57c821c75b54923eb85c69595004dc20', '2024-01-26 01:44:55', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1594, 'laike-plugin-presell-demo.yml', 'DEFAULT_GROUP', 'server:\n  port: :19001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /presell\n\nnode:\n  ip: 0.0.0.0\n\n#dubbo:\n#  application:\n#    name: laike-presell\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 21924\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-plugin-presell\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21924}\n  \n\n#swagger 配置\nswagger:\n  title: 来客电商-预售接口\n  desc: 来客电商预售接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.presell\n  groupName: 预售\n  contactName: presell\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com', '8248c58284c18efe38298d67a9d11aa8', '2024-01-26 01:44:55', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', 'java主线预售', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1595, 'laike-plugin-diy-demo.yml', 'DEFAULT_GROUP', 'server:\n  port: 19001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /diy\n    \nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-diy\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20904}\n\n#swagger 配置\nswagger:\n  title: 来客电商-diy模板接口\n  desc: 来客电商diy模板接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.diy\n  groupName: diy模板\n  contactName: diy\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com\n', '3a3d428f69d7eb699689d4d7bc73a13e', '2024-01-26 01:44:55', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1596, 'laike-plugin-coupon-demo.yml', 'DEFAULT_GROUP', 'server:\n  port: 18001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /coupon\n\nnode:\n  ip: 0.0.0.0\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-coupon\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21894}\n\n\n#swagger 配置\nswagger:\n  title: 来客电商-优惠卷接口\n  desc: 来客电商优惠卷接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.coupon\n  groupName: 优惠卷\n  contactName: coupon\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n  \n', '7613ed40fa57acd474cc03bf8ef2e79e', '2024-01-26 01:44:55', '2024-01-26 01:44:55', NULL, '0:0:0:0:0:0:0:1', '', '41b2716b-f0ea-443b-a9e1-481bdde0c62f', '优惠券模块', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (1933, 'laike-cloud-gateway-prod.yml', 'DEFAULT_GROUP', 'server:\n  port: 9528\n    \nspring:\n  cloud:\n    gateway:\n      # 处理跨域请求\n      globalcors:\n        add-to-simple-url-handler-mapping: true\n        cors-configurations:\n          \'[/**]\':\n            allowedHeaders: \"*\"\n            allowedOrigins: \"*\"\n            allowCredentials: true\n            allowedMethods:\n              - GET\n              - POST\n              - DELETE\n              - HEAD\n              - PUT\n              - OPTION \n      default-filters:\n            - DedupeResponseHeader=Vary Access-Control-Allow-Origin Access-Control-Allow-Credentials, RETAIN_FIRST\n\n      routes:\n        # 配置模块路由\n        # PC店铺端接口\n        - id: admin-mch\n          uri: lb://admin-mch\n          predicates:\n            - Path=/admin-mch/**\n#          filters:\n#            - StripPrefix=1\n        # 商城管理后台\n        - id: admin\n          uri: lb://admin\n          predicates:\n            - Path=/admin/**,/saas/**\n        #  filters:\n        #   - StripPrefix=1\n        # 供应商\n        - id: supplier\n          uri: lb://supplier\n          predicates:\n            - Path=/supplier/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端接口\n        - id: app\n          uri: lb://app\n          predicates:\n            - Path=/app/**\n#          filters:\n#            - StripPrefix=1\n        # 优惠券\n        - id: coupon\n          uri: lb://coupon\n          predicates:\n            - Path=/coupon/**\n#          filters:\n#            - StripPrefix=1\n        # 首页DIY\n        - id: diy\n          uri: lb://diy\n          predicates:\n            - Path=/diy/**\n#          filters:\n#            - StripPrefix=1\n        # 资源文件\n        - id: file\n          uri: lb://file\n          predicates:\n            - Path=/file/**\n#          filters:\n#            - StripPrefix=1\n        # 运费\n        - id: freight\n          uri: lb://freight\n          predicates:\n            - Path=/freight/**\n#          filters:\n#            - StripPrefix=1\n        # 网关\n        - id: gateway\n          uri: lb://gateway\n          predicates:\n            - Path=/gw/**,/gateway/**\n        # 发票\n        - id: invoice\n          uri: lb://invoice\n          predicates:\n            - Path=/invoice/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端店铺接口\n        - id: mch\n          uri: lb://mch\n          predicates:\n            - Path=/mch/**\n#          filters:\n#            - StripPrefix=1\n        # 会员制\n        - id: member\n          uri: lb://member\n          predicates:\n            - Path=/member/**\n#          filters:\n#            - StripPrefix=1\n        # 订单\n        - id: order\n          uri: lb://order\n          predicates:\n            - Path=/order/**\n#          filters:\n#            - StripPrefix=1\n        # 支付\n        - id: payment\n          uri: lb://payment\n          predicates:\n            - Path=/payment/**\n#          filters:\n#            - StripPrefix=1\n        # 竞拍\n        - id: auction\n          uri: lb://auction\n          predicates:\n            - Path=/auction/**\n#          filters:\n#            - StripPrefix=1\n        # 分销\n        - id: distribute\n          uri: lb://distribute\n          predicates:\n            - Path=/distribute/**\n#          filters:\n#            - StripPrefix=1\n        # 拼团\n        - id: group\n          uri: lb://group\n          predicates:\n            - Path=/group/**\n#          filters:\n#            - StripPrefix=1\n        #\n        - id: integral\n          uri: lb://integral\n          predicates:\n            - Path=/integral/**\n#          filters:\n#            - StripPrefix=1\n        # 签到\n        - id: sign\n          uri: lb://sign\n          predicates:\n            - Path=/sign/**\n#          filters:\n#            - StripPrefix=1\n        # 预售\n        - id: presell\n          uri: lb://presell\n          predicates:\n            - Path=/presell/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端商品\n        - id: products\n          uri: lb://products\n          predicates:\n            - Path=/products/**\n#          filters:\n#            - StripPrefix=1\n        # 秒杀\n        - id: seckill\n          uri: lb://seckill\n          predicates:\n            - Path=/seckill/**\n#          filters:\n#            - StripPrefix=1\n        # PC商城\n        - id: mall\n          uri: lb://mall\n          predicates:\n            - Path=/mall/**\n#          filters:\n#            - StripPrefix=1\n        # 定时任务\n        - id: laike-task\n          uri: lb://laike-task\n          predicates:\n            - Path=/task/**\n#          filters:\n#            - StripPrefix=1\n        # 用户信息\n        - id: user\n          uri: lb://user\n          predicates:\n            - Path=/user/**\n          # filters:\n          #   - StripPrefix=1\n        # seata\n        - id: seata-demo\n          uri: lb://seata-demo\n          predicates:\n            - Path=/seata-demo/**\n          # filters:\n          #   - StripPrefix=1\n        - id: flashsale\n          uri: lb://flashsale\n          predicates:\n            - Path=/flashsale/**\n          # filters:\n          #   - StripPrefix=1', 'c5d156c1e502ec4b9bd03484bcba1609', '2024-01-31 08:01:51', '2024-04-03 09:42:58', 'nacos', '175.13.104.119', '', '23467031-bda4-48a0-a7ab-6bc1a4be22fd', 'springcloud gateway网关模块', '', '', 'yaml', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2004, 'laike-user-test.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: 18002\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /user\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\n# dubbo:\n#   application:\n#     name: laike-user\n#     # 禁用QOS同一台机器可能会有端口冲突现象\n#     qos-enable: false\n#     qos-accept-foreign-ip: false\n#     # 配置注册中心\n#   registry:\n#     address: nacos://localhost:8848\n#   # 设置超时时间\n#   consumer:\n#     timeout: 6000\n#   protocol:\n#     name: dubbo\n#     port: ${NACOS_PORT:21889} \n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-user\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21889} \n\n#swagger 配置\nswagger:\n  title: 来客电商-用户接口\n  desc: 来客电商用户接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.user\n  groupName: 用户\n  contactName: user\n  contactUrl: http://www.laiketui.com/\n  contactEmail:', '613f517ae4b524124cea25c583a62d78', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '用户', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2005, 'laike-task-test.yml', 'DEFAULT_GROUP', 'server:\n  port: 18001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /task\n    \nnode:\n  ip: 0.0.0.0\n\n#dubbo:\n#  application:\n#    name: laike_app\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 21898\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-task\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21898}\n\n# logging:\n#   level:\n#     com:\n#       laiketui: info\n#   config: classpath:logback-spring.xml\n\n#swagger 配置\nswagger:\n  title: 来客电商-任务调度\n  desc: 来客电商任务调度\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.task\n  groupName: 任务调度\n  contactName: task\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n#xxl-job\nxxl:\n  job:\n    accessToken:\n    admin:\n      addresses: http://127.0.0.1:3366/task # 任务调度中心部署根地址（必填）\n    executor:\n      appname: laike-task                   # 对应 执行管理器 AppName\n      ip: 127.0.0.1                         # 执行器ip，可以不填，会自动识别注册\n      logpath: ./task.log                   # 执行器运行日志文件存储磁盘路径\n      logretentiondays: 30                  # 执行器日志保存天数，值大于3时生效，启用执行器log文件定期清理功能，否则不生效。\n      port: 2024                           # 执行器端口号 \n      #AccessToken：执行器通讯token，非空时启用', '764116dd396cf20b14541304f02721c1', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '定时任务', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2006, 'laike-store-pc-test.yml', 'DEFAULT_GROUP', 'server:\n  port: 18002\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /mall\n    \nnode:\n  ip: 0.0.0.0\n\n#dubbo:\n#  application:\n#    name: laike-pcmall\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 21900\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-store-pc\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21900}\n\n\n#swagger 配置\nswagger:\n  title: 来客电商-pc商城\n  desc: 来客电商[pc商城]API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.store.pc\n  groupName: mall\n  contactName: mall\n  contactUrl: http://www.laiketui.com/\n  contactEmail:', '2825dc2d7a522bb7f1e02c9eeba2ee62', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', 'pc商城', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2007, 'laike-products-test.yml', 'DEFAULT_GROUP', 'server:\n  port: 18002\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /product\n    \nnode:\n  ip: 0.0.0.0\n\n#dubbo:\n#  application:\n#    name: laike-products\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: ${ZOOKEEPER_PORT:21897}\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-products\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21897}  \n\n#swagger 配置\nswagger:\n  title: 来客电商-商品接口\n  desc: 来客电商商品接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.products\n  groupName: 商品\n  contactName: product\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n', '3b2d145efab685f8c23080d675e13d81', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '商品模块', NULL, NULL, 'yaml', NULL, '');
