INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2017, 'laike-mch-test.yml', 'DEFAULT_GROUP', 'server:\n  port: 18002\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet: \n    context-path: /mch\n    \nnode:\n  ip: 0.0.0.0\n\n#dubbo:\n#  application:\n#    name: laike-mch\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: ${ZOOKEEPER_PORT:20992}\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-mch\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20992}\n\n#swagger 配置\nswagger:\n  title: 来客电商-店铺接口\n  desc: 来客电商店铺接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.mch\n  groupName: 店铺\n  contactName: mch\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n', '8d6056c3970e4ae2fc9f9029faead2bb', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '移动端店铺模块', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2018, 'laike-invoice-test.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: 18001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /invoice\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 0.0.0.0\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-invoice\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21890}\n \n\n#swagger 配置\nswagger:\n  title: 来客电商-发票接口\n  desc: 来客电商发票接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.invoice\n  groupName: 发票\n  contactName: invoice\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n  ', 'a38d0ea46192bc04f0b7269b7da9c814', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '发票模块', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2019, 'laike-gateway-test.yml', 'DEFAULT_GROUP', 'server:\n  port: 18001\n  tomcat:\n    uri-encoding: UTF-8\n  ssl:\n    enabled: false\n    connection-timeout: 20000\n\nspring:\n  main:\n    allow-bean-definition-overriding: true\n  jmx:\n    enabled: false\n  application:\n    name: laike-gateway\n  resources:\n    static-locations: classpath:/static/\n  mvc:\n    static-path-pattern: /gw/images/**\n  servlet:\n    multipart:\n      max-file-size: 10MB\n      max-request-size: 30MB\n      file-size-threshold: 1\n  multipart:\n    # 上传文件的临时目录\n    location: /upload\n  http:\n    encoding:\n      force: true\n      charset: UTF-8\n      enabled: true\n  messages:\n    basenames: i18n/tips\n    encoding: UTF-8\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-gateway\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20888}\n\n', 'f86a3dd251c802dcbd5f3fa8910c2998', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '网关模块', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2020, 'laike-freight-test.yml', 'DEFAULT_GROUP', 'server:\n  port: 18002\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /freight\n    \nnode:\n  ip: 0.0.0.0\n\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-freight\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21890}\n\n\n\n#swagger 配置\nswagger:\n  title: 来客电商-运费接口\n  desc: 来客电商运费接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.freight\n  groupName: 运费\n  contactName: freight\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n\n', '1d7303249b6834138cbcf0c7217fc4ce', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '运费模块', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2021, 'laike-file-test.yml', 'DEFAULT_GROUP', 'server:\n  port: 18001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /file\n    \nnode:\n  ip: 0.0.0.0\n#dubbo:\n#  application:\n#    name: laike-file\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 21892\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-file\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21892}\n\n#swagger 配置\nswagger:\n  title: 来客电商-资源上传\n  desc: 来客电商后台资源上传API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.file\n  groupName: 资源上传\n  contactName: file\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n', '4c8138ecd4b0b90d9f54d6e475619833', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '资源模块', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2022, 'comm-test.yml', 'DEFAULT_GROUP', 'spring:\n  cloud:\n    nacos: \n      discovery:\n        ip: localhost\n    sentinel:\n      transport:\n        dashboard: 127.0.0.1:9527\n        port: 8719\n      eager: true\n  redis:\n    host: localhost\n    port: 6339\n    password: laiketui18\n    lettuce:\n      pool:\n        # 连接池中的最大空闲连接 默认8\n        max-idle: 100\n        # 连接池中的最小空闲连接 默认0\n        min-idle: 0\n        # 连接池最大连接数 默认8 ，负数表示没有限制\n        max-active: 20\n        # 连接池最大阻塞等待时间（使用负值表示没有限制） 默认-1\n        max-wait: -1\n    timeout: 30000\n    database: 5\n  # =======================shardingsphere 读写分离先搭建好主从库，再到这边配置 =============================\n  shardingsphere:\n    # 是否开启SQL显示\n    # props:\n    #   sql:\n    #     show: true \n    datasource:\n      # names: lkt-ds-master-0,ds-slave-0-1\n      names: lkt-ds-master-0\n      #主库-写库 \n      # lkt-ds-master-0:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3307/java_main_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root\n      #主库-从库-读库 可多个从库 这里主从都是用的同一个库\n      # ds-slave-0-1:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3308/java_main_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root \n      #主库-写库\n      lkt-ds-master-0: \n        # url: jdbc:mysql://47.107.123.240:3306/v3_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        # username: root\n        # password: 51bbec4bcde2ef40\n        # url: jdbc:mysql://192.168.0.48:3306/v3_24db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        # username: root\n        # password: root\n        # &amp;allowMultiQueries=true&amp;rewriteBatchedStatements=true&amp;failOverReadOnly=false&amp;serverTimezone=UTC\n        # url: jdbc:mysql://47.107.123.240:3316/v3_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        # url: jdbc:mysql://localhost:3306/v3_new_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&connectTimeout=300000&socketTimeout=600000\n        url: jdbc:mysql://localhost:3316/v3_db?useUnicode=true&autoReconnect=true&failOverReadOnly=false&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false&allowMultiQueries=true&rewriteBatchedStatements=true&connectTimeout=300000&socketTimeout=600000\n        username: root\n        password: 123456\n        # password: 51bbec4bcde2ef40\n        type: com.alibaba.druid.pool.DruidDataSource\n        # type: com.zaxxer.hikari.HikariDataSource\n        driver-class-name: com.mysql.cj.jdbc.Driver \n        initial-size: 10\n        min-idle: 2\n        maxActive: 10\n        # 配置获取连接等待超时的时间\n        maxWait: 60000\n        # 配置间隔多久才进行一次检测，检测需要关闭的空闲连接，单位是毫秒\n        timeBetweenEvictionRunsMillis: 6000\n        # 配置一个连接在池中最小生存的时间，单位是毫秒\n        minEvictableIdleTimeMillis: 30000\n        minEvictableEvictionTimeMillis: 6000000\n        validationQuery: select 1\n        testWhileIdle: true\n        testOnBorrow: false\n        testOnReturn: false\n        # 打开PSCache，并且指定每个连接上PSCache的大小\n        poolPreparedStatements: true\n        maxPoolPreparedStatementPerConnectionSize: 20\n        # 配置监控统计拦截的filters，去掉后监控界面sql无法统计，\'wall\'用于防火墙\n        filters: stat,wall,slf4j\n        # 通过connectProperties属性来打开mergeSql功能；慢SQL记录\n        connectionProperties: druid.stat.mergeSql\\=true;druid.stat.slowSqlMillis\\=50000\n        wall:\n          multi-statement-allow: true\n      #主库-从库-读库 可多个从库 这里主从都是用的同一个库\n      # ds-slave-0-1:\n      #   type: com.alibaba.druid.pool.DruidDataSource\n      #   driver-class-name: com.mysql.cj.jdbc.Driver\n      #   url: jdbc:mysql://localhost:3308/java_main_db?useUnicode=true&autoReconnect=true&characterEncoding=utf-8&serverTimezone=GMT%2B8&zeroDateTimeBehavior=convertToNull&tinyInt1isBit=false\n      #   username: root\n      #   password: root \n      #   testWhileIdle: true\n    # 读写分离配置，需要的时候打开这个注释\n    #masterslave:\n    #  name: lkt-ms\n    #  load-balance-algorithm-type: round_robin\n    #  master-data-source-name: lkt-ds-master-0\n    #  slave-data-source-names: ds-slave-0-1\n\n  flyway:\n    enabled: false\n  jmx:\n    enabled: false\n  http:\n    encoding:\n      force: true\n      charset: UTF-8\n      enabled: true\n  servlet:\n    multipart:\n      max-file-size: 500MB\n      max-request-size: 500MB\n      file-size-threshold: 1\n  messages:\n   fallbackToSystemLocale: false\n   basename: i18n/tips\n   encoding: UTF-8\n\n#文件上传路径\nuploadFile:\n  path: /usr/local/imgs/\n\n#日志级别\nlogging:\n  config: classpath:logback-spring.xml\n  level:\n    com:\n      laiketui: info\n      \n##集群用\",\"连接\n# elasticSearch:\n#   hostlist: 47.107.123.240:19200\n#   client:\n#     connectNum: 10\n#     connectPerRoute: 3\n\nlkt-gateway:\n  # 单个IP每分钟请求次数上线\n  request_limit_perip:\n    limit: 150\n    # 默认是一分钟：60秒\n    time: 60\n\n  #black ip 黑名单 禁止访问 \n  blacklist:\n    ips: 192.168.0.222\n\nfeign:\n  hystrix:\n    enabled: false\n    \nribbon:\n  ReadTimeout: 10000\n  ConnectTimeout: 10000\n    \n# seata配置\nseata:\n  enabled: true\n  # Seata 应用编号，默认为 ${spring.application.name}\n  application-id: ${spring.application.name}\n  # Seata 事务组编号，用于 TC 集群名\n  tx-service-group: mygroup\n  # 关闭自动代理\n  # enable-auto-data-source-proxy: false\n  enableAutoDataSourceProxy: false\n  # use-jdk-proxy: true\n  # 服务配置项\n  service:\n    # 虚拟组和分组的映射\n    vgroup-mapping:\n      mygroup: default\n    # seeata 所在服务器的端口要打开 8091 \n    # grouplist:\n    #   default: 1.2.3.4:8091\n  # config:\n  #   type: nacos\n  #   nacos:\n  #     server-addr: 47.107.123.240:8848\n  #     namespace: da8f7d37-960a-4c94-9691-9c77711d995c\n  #     # 这是默认值\n  #     data-id: seataServer-dev.properties\n  #     # 这是默认值\n  #     group: DEFAULT_GROUP\n\n  # registry:\n  #   type: nacos\n  #   nacos:\n  #     server-addr: 47.107.123.240:8848\n  #     namespace: da8f7d37-960a-4c94-9691-9c77711d995c \n  #     #默认值和 config 的 SEATA_GROUP 不一样 \n  #     group: DEFAULT_GROUP ', '12fb63bac161b29b38dfe27f0b4ba8d6', '2024-02-01 03:32:26', '2024-08-26 06:17:18', 'nacos', '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '各个环境都一样的配置', '', '', 'yaml', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2023, 'seataServer-test.properties', 'DEFAULT_GROUP', '#For details about configuration items, see https://seata.io/zh-cn/docs/user/configurations.html\n#Transport configuration, for client and server\ntransport.type=TCP\ntransport.server=NIO\ntransport.heartbeat=true\ntransport.enableTmClientBatchSendRequest=false\ntransport.enableRmClientBatchSendRequest=true\ntransport.enableTcServerBatchSendResponse=false\ntransport.rpcRmRequestTimeout=30000\ntransport.rpcTmRequestTimeout=30000\ntransport.rpcTcRequestTimeout=30000\ntransport.threadFactory.bossThreadPrefix=NettyBoss\ntransport.threadFactory.workerThreadPrefix=NettyServerNIOWorker\ntransport.threadFactory.serverExecutorThreadPrefix=NettyServerBizHandler\ntransport.threadFactory.shareBossWorker=false\ntransport.threadFactory.clientSelectorThreadPrefix=NettyClientSelector\ntransport.threadFactory.clientSelectorThreadSize=1\ntransport.threadFactory.clientWorkerThreadPrefix=NettyClientWorkerThread\ntransport.threadFactory.bossThreadSize=1\ntransport.threadFactory.workerThreadSize=default\ntransport.shutdown.wait=3\ntransport.serialization=seata\ntransport.compressor=none\n\n#Transaction routing rules configuration, only for the client\n# 此处的mygroup名字可以自定义，只修改这个值即可\nservice.vgroupMapping.mygroup=default\n#If you use a registry, you can ignore it\n#service.default.grouplist=127.0.0.1:8091\n#service.enableDegrade=false\n#service.disableGlobalTransaction=false\n\n#Transaction rule configuration, only for the client\nclient.rm.asyncCommitBufferLimit=10000\nclient.rm.lock.retryInterval=10\nclient.rm.lock.retryTimes=30\nclient.rm.lock.retryPolicyBranchRollbackOnConflict=true\nclient.rm.reportRetryCount=5\nclient.rm.tableMetaCheckEnable=true\nclient.rm.tableMetaCheckerInterval=60000\nclient.rm.sqlParserType=druid\nclient.rm.reportSuccessEnable=false\nclient.rm.sagaBranchRegisterEnable=false\nclient.rm.sagaJsonParser=fastjson\nclient.rm.tccActionInterceptorOrder=-2147482648\nclient.tm.commitRetryCount=5\nclient.tm.rollbackRetryCount=5\nclient.tm.defaultGlobalTransactionTimeout=60000\nclient.tm.degradeCheck=false\nclient.tm.degradeCheckAllowTimes=10\nclient.tm.degradeCheckPeriod=2000\nclient.tm.interceptorOrder=-2147482648\nclient.undo.dataValidation=true\nclient.undo.logSerialization=jackson\nclient.undo.onlyCareUpdateColumns=true\nserver.undo.logSaveDays=7\nserver.undo.logDeletePeriod=86400000\nclient.undo.logTable=undo_log\nclient.undo.compress.enable=true\nclient.undo.compress.type=zip\nclient.undo.compress.threshold=64k\n#For TCC transaction mode\ntcc.fence.logTableName=tcc_fence_log\ntcc.fence.cleanPeriod=1h\n\n#Log rule configuration, for client and server\nlog.exceptionRate=100\n\n#Transaction storage configuration, only for the server. The file, db, and redis configuration values are optional.\n# 默认为file，一定要改为db，我们自己的服务启动会连接不到seata\nstore.mode=db\nstore.lock.mode=db\nstore.session.mode=db\n#Used for password encryption\n\n#These configurations are required if the `store mode` is `db`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `db`, you can remove the configuration block.\n# 修改mysql的配置\nstore.db.datasource=druid\nstore.db.dbType=mysql\nstore.db.driverClassName=com.mysql.cj.jdbc.Driver\n# 指定seata的数据库，下面会提\nstore.db.url=jdbc:mysql://localhost:3306/seata_db?useUnicode=true&rewriteBatchedStatements=true\nstore.db.user=root\nstore.db.password=51bbec4bcde2ef40\nstore.db.minConn=5\nstore.db.maxConn=30\nstore.db.globalTable=global_table\nstore.db.branchTable=branch_table\nstore.db.distributedLockTable=distributed_lock\nstore.db.queryLimit=100\nstore.db.lockTable=lock_table\nstore.db.maxWait=50000\n\n\n#Transaction rule configuration, only for the server\nserver.recovery.committingRetryPeriod=600000\nserver.recovery.asynCommittingRetryPeriod=600000\nserver.recovery.rollbackingRetryPeriod=600000\nserver.recovery.timeoutRetryPeriod=600000\nserver.maxCommitRetryTimeout=-1\nserver.maxRollbackRetryTimeout=-1\nserver.rollbackRetryTimeoutUnlockEnable=false\nserver.distributedLockExpireTime=600000\nserver.xaerNotaRetryTimeout=600000\nserver.session.branchAsyncQueueSize=50000\nserver.session.enableBranchAsyncRemove=false\nserver.enableParallelRequestHandle=false\n\n#Metrics configuration, only for the server\nmetrics.enabled=false\nmetrics.registryType=compact\nmetrics.exporterList=prometheus\nmetrics.exporterPrometheusPort=9898\n', 'd0de8496fe3c0c53b6e7c33528882417', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', 'seata本地环境', NULL, NULL, 'properties', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2024, 'service.vgroupMapping.mygroup', 'DEFAULT_GROUP', 'default', 'c21f969b5f03d33d43e04f8f136e7682', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '', NULL, NULL, 'text', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2025, 'laike-plugins-mybatis.yml', 'DEFAULT_GROUP', 'mybatis:\n  mapper-locations: classpath:/db/mapping/*Mapper.xml\n  type-aliases-package: com.laiketui.plugin.common.domain.base\n  mapper:\n    identity: MYSQL\n    mappers: tk.mybatis.mapper.commgeneratoron.Mapper\n    not-empty: true\n  ######### 分页插件 ##########\n  pagehelper:\n    helper-dialect: mysql\n    reasonable: true\n    params: count=countSql\n    support-methods-arguments: true', '715d8ab1156e87f5173d70d957af86fb', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2026, 'laike-base-mybatis.yml', 'DEFAULT_GROUP', 'mybatis:\n  mapper-locations: classpath:/db/mapping/*Mapper.xml\n  type-aliases-package: com.laiketui.domain\n  mapper:\n    identity: MYSQL\n    mappers: tk.mybatis.mapper.commgeneratoron.Mapper\n    not-empty: true\n  ######### 分页插件 ##########\n  pagehelper:\n    helper-dialect: mysql\n    reasonable: true\n    params: count=countSql\n    support-methods-arguments: true', 'f91c71660e4418c7f81bc400f6f448f2', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2027, 'laike-plugin-group-test.yml', 'DEFAULT_GROUP', 'server:\n  port: 19001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /group\n    \nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-plugin-group\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21905}\n\n\n#swagger 配置\nswagger:\n  title: 来客电商-拼团接口\n  desc: 来客电商拼团接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.group\n  groupName: 拼团\n  contactName: group\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com', '8c00112d3ed0edd636232d36d1446a20', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', '拼团', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2028, 'laike-online-message-test.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: 18180\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /message\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-online-message\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21897} \n\n#swagger 配置\nswagger:\n  title: 来客电商-在线聊天\n  desc: 来客电商在线聊天接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.online.message\n  groupName: 在线聊天\n  contactName: message\n  contactUrl: http://www.laiketui.com/\n  contactEmail:', '925acbf4b5506b21f2fa7a7565316607', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', 'im服务配置', NULL, NULL, 'yaml', NULL, '');
