INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2034, 'laike-plugin-flashsale-test.yml', 'DEFAULT_GROUP', 'server:\n  port: 19001\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /flashsale\n    \nnode:\n  ip: 0.0.0.0\n\n#dubbo:\n#  application:\n#    name: laike-seckill\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 21904\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-plugin-flashsale\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:32154}\n\n#swagger 配置\nswagger:\n  title: 来客电商-限时闪购接口\n  desc: 来客电商限时闪购接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.flashsale\n  groupName: 限时闪购\n  contactName: flashsale\n  contactUrl: http://www.laiketui.com/\n  contactEmail: 36309839@qq.com', 'b162084afddf564096ea5b400263cbf1', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', 'java主线限时闪购', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (2035, 'laike-cloud-gateway-test.yml', 'DEFAULT_GROUP', 'server:\n  port: 18002 \n    \nspring:\n  cloud:\n    gateway:\n      # 处理跨域请求\n      globalcors:\n        add-to-simple-url-handler-mapping: true\n        cors-configurations:\n          \'[/**]\':\n            allowedHeaders: \"*\"\n            allowedOrigins: \"*\"\n            allowCredentials: true\n            allowedMethods:\n              - GET\n              - POST\n              - DELETE\n              - HEAD\n              - PUT\n              - OPTION \n      default-filters:\n            - DedupeResponseHeader=Vary Access-Control-Allow-Origin Access-Control-Allow-Credentials, RETAIN_FIRST\n\n      routes:\n        # 配置模块路由\n        # PC店铺端接口\n        - id: admin-mch\n          uri: lb://admin-mch\n          predicates:\n            - Path=/admin-mch/**\n#          filters:\n#            - StripPrefix=1\n        # 商城管理后台\n        - id: admin\n          uri: lb://admin\n          predicates:\n            - Path=/admin/**,/saas/**\n        #  filters:\n        #   - StripPrefix=1\n        # 供应商\n        - id: supplier\n          uri: lb://supplier\n          predicates:\n            - Path=/supplier/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端接口\n        - id: app\n          uri: lb://app\n          predicates:\n            - Path=/app/**\n#          filters:\n#            - StripPrefix=1\n        # 优惠券\n        - id: coupon\n          uri: lb://coupon\n          predicates:\n            - Path=/coupon/**\n#          filters:\n#            - StripPrefix=1\n        # 首页DIY\n        - id: diy\n          uri: lb://diy\n          predicates:\n            - Path=/diy/**\n#          filters:\n#            - StripPrefix=1\n        # 资源文件\n        - id: file\n          uri: lb://file\n          predicates:\n            - Path=/file/**\n#          filters:\n#            - StripPrefix=1\n        # 运费\n        - id: freight\n          uri: lb://freight\n          predicates:\n            - Path=/freight/**\n#          filters:\n#            - StripPrefix=1\n        # 网关\n        - id: gateway\n          uri: lb://gateway\n          predicates:\n            - Path=/gw/**,/gateway/**\n        # 发票\n        - id: invoice\n          uri: lb://invoice\n          predicates:\n            - Path=/invoice/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端店铺接口\n        - id: mch\n          uri: lb://mch\n          predicates:\n            - Path=/mch/**\n#          filters:\n#            - StripPrefix=1\n        # 会员制\n        - id: member\n          uri: lb://member\n          predicates:\n            - Path=/member/**\n#          filters:\n#            - StripPrefix=1\n        # 订单\n        - id: order\n          uri: lb://order\n          predicates:\n            - Path=/order/**\n#          filters:\n#            - StripPrefix=1\n        # 支付\n        - id: payment\n          uri: lb://payment\n          predicates:\n            - Path=/payment/**\n#          filters:\n#            - StripPrefix=1\n        # 竞拍\n        - id: auction\n          uri: lb://auction\n          predicates:\n            - Path=/auction/**\n#          filters:\n#            - StripPrefix=1\n        # 分销\n        - id: distribute\n          uri: lb://distribute\n          predicates:\n            - Path=/distribute/**\n#          filters:\n#            - StripPrefix=1\n        # 拼团\n        - id: group\n          uri: lb://group\n          predicates:\n            - Path=/group/**\n#          filters:\n#            - StripPrefix=1\n        #\n        - id: integral\n          uri: lb://integral\n          predicates:\n            - Path=/integral/**\n#          filters:\n#            - StripPrefix=1\n        # 签到\n        - id: sign\n          uri: lb://sign\n          predicates:\n            - Path=/sign/**\n#          filters:\n#            - StripPrefix=1\n        # 预售\n        - id: presell\n          uri: lb://presell\n          predicates:\n            - Path=/presell/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端商品\n        - id: products\n          uri: lb://products\n          predicates:\n            - Path=/products/**\n#          filters:\n#            - StripPrefix=1\n        # 秒杀\n        - id: seckill\n          uri: lb://seckill\n          predicates:\n            - Path=/seckill/**\n#          filters:\n#            - StripPrefix=1\n        # PC商城\n        - id: mall\n          uri: lb://mall\n          predicates:\n            - Path=/mall/**\n#          filters:\n#            - StripPrefix=1\n        # 定时任务\n        - id: laike-task\n          uri: lb://laike-task\n          predicates:\n            - Path=/task/**\n#          filters:\n#            - StripPrefix=1\n        # 用户信息\n        - id: user\n          uri: lb://user\n          predicates:\n            - Path=/user/**\n          # filters:\n          #   - StripPrefix=1\n        # seata\n        - id: seata-demo\n          uri: lb://seata-demo\n          predicates:\n            - Path=/seata-demo/**\n          # filters:\n          #   - StripPrefix=1\n        - id: flashsale\n          uri: lb://flashsale\n          predicates:\n            - Path=/flashsale/**\n          # filters:\n          #   - StripPrefix=1', 'bea0f15679180c3b56d080b23b060e63', '2024-02-01 03:32:26', '2024-02-01 03:32:26', NULL, '127.0.0.1', '', 'a8d5eeb0-856f-4cdb-afe3-0fbd8d5bb597', 'springcloud gateway网关模块', NULL, NULL, 'yaml', NULL, '');
