INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (7159, 'com.laiketui.app.api.seatMap.SeatMapDubboService', 'mapping', 'laike-app', '2d2238fdf96955db8be663db827b1c23', '2024-06-03 09:33:44', '2024-06-03 09:33:44', NULL, '192.168.40.1', '', '', NULL, NULL, NULL, 'text', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (8841, 'laike-cloud-gateway-dev.yml', 'DEFAULT_GROUP', 'server:\n  port: 9526\n  servlet:\n    context-path: /scgw\n    \nspring:\n  cloud:\n    gateway:\n      # 处理跨域请求\n      globalcors:\n        add-to-simple-url-handler-mapping: true\n        cors-configurations:\n          \'[/**]\':\n            allowedHeaders: \"*\"\n            allowedOrigins: \"*\"\n            allowCredentials: true\n            allowedMethods:\n              - GET\n              - POST\n              - DELETE\n              - HEAD\n              - PUT\n              - OPTION \n      default-filters:\n            - DedupeResponseHeader=Vary Access-Control-Allow-Origin Access-Control-Allow-Credentials, RETAIN_FIRST\n\n      routes:\n        # 配置模块路由\n        # PC店铺端接口\n        - id: admin-mch\n          uri: lb://admin-mch\n          predicates:\n            - Path=/admin-mch/**\n#          filters:\n#            - StripPrefix=1\n        # 商城管理后台\n        - id: admin\n          uri: lb://admin\n          predicates:\n            - Path=/admin/**,/saas/**\n        #  filters:\n        #   - StripPrefix=1\n        # 供应商\n        - id: supplier\n          uri: lb://supplier\n          predicates:\n            - Path=/supplier/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端接口\n        - id: app\n          uri: lb://app\n          predicates:\n            - Path=/app/**\n#          filters:\n#            - StripPrefix=1\n        # 优惠券\n        - id: coupon\n          uri: lb://coupon\n          predicates:\n            - Path=/coupon/**\n#          filters:\n#            - StripPrefix=1\n        # 首页DIY\n        - id: diy\n          uri: lb://diy\n          predicates:\n            - Path=/diy/**\n#          filters:\n#            - StripPrefix=1\n        # 资源文件\n        - id: file\n          uri: lb://file\n          predicates:\n            - Path=/file/**\n#          filters:\n#            - StripPrefix=1\n        # 运费\n        - id: freight\n          uri: lb://freight\n          predicates:\n            - Path=/freight/**\n#          filters:\n#            - StripPrefix=1\n        # 网关\n        - id: gateway\n          uri: lb://gateway\n          predicates:\n            - Path=/gw/**\n        # 发票\n        - id: invoice\n          uri: lb://invoice\n          predicates:\n            - Path=/invoice/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端店铺接口\n        - id: mch\n          uri: lb://mch\n          predicates:\n            - Path=/mch/**\n#          filters:\n#            - StripPrefix=1\n        # 会员制\n        - id: member\n          uri: lb://member\n          predicates:\n            - Path=/member/**\n#          filters:\n#            - StripPrefix=1\n        # 订单\n        - id: order\n          uri: lb://order\n          predicates:\n            - Path=/order/**\n#          filters:\n#            - StripPrefix=1\n        # 支付\n        - id: payment\n          uri: lb://payment\n          predicates:\n            - Path=/payment/**\n#          filters:\n#            - StripPrefix=1\n        # 竞拍\n        - id: auction\n          uri: lb://auction\n          predicates:\n            - Path=/auction/**\n#          filters:\n#            - StripPrefix=1\n        # 分销\n        - id: distribute\n          uri: lb://distribute\n          predicates:\n            - Path=/distribute/**\n#          filters:\n#            - StripPrefix=1\n        # 拼团\n        - id: group\n          uri: lb://group\n          predicates:\n            - Path=/group/**\n#          filters:\n#            - StripPrefix=1\n        #\n        - id: integral\n          uri: lb://integral\n          predicates:\n            - Path=/integral/**\n#          filters:\n#            - StripPrefix=1\n        # 签到\n        - id: sign\n          uri: lb://sign\n          predicates:\n            - Path=/sign/**\n#          filters:\n#            - StripPrefix=1\n        # 预售\n        - id: presell\n          uri: lb://presell\n          predicates:\n            - Path=/presell/**\n#          filters:\n#            - StripPrefix=1\n        # 移动端商品\n        - id: products\n          uri: lb://products\n          predicates:\n            - Path=/products/**\n#          filters:\n#            - StripPrefix=1\n        # 秒杀\n        - id: seckill\n          uri: lb://seckill\n          predicates:\n            - Path=/seckill/**\n#          filters:\n#            - StripPrefix=1\n        # PC商城\n        - id: mall\n          uri: lb://mall\n          predicates:\n            - Path=/mall/**\n#          filters:\n#            - StripPrefix=1\n        # 定时任务\n        - id: laike-task\n          uri: lb://laike-task\n          predicates:\n            - Path=/task/**\n#          filters:\n#            - StripPrefix=1\n        # 用户信息\n        - id: user\n          uri: lb://user\n          predicates:\n            - Path=/user/**\n          # filters:\n          #   - StripPrefix=1\n        # seata\n        - id: seata-demo\n          uri: lb://seata-demo\n          predicates:\n            - Path=/seata-demo/**\n          # filters:\n          #   - StripPrefix=1\n        - id: flashsale\n          uri: lb://flashsale\n          predicates:\n            - Path=/flashsale/**\n          # filters:\n          #   - StripPrefix=1', 'ec1e93bd73f6fd4113f67a13f789797b', '2024-06-17 02:25:15', '2024-06-17 02:25:15', NULL, '0:0:0:0:0:0:0:1', '', 'da8f7d37-960a-4c94-9691-9c77711d995c', 'springcloud gateway网关模块', NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (8844, 'laike-plugin-living-prod.yml', 'DEFAULT_GROUP', 'server:\n  port: ${TOMCAT_PORT:18180}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /living\n    \nnode:\n  ip: 0.0.0.0\n \n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-plugin-living\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:20926}\n\n#swagger 配置\nswagger:\n  title: 来客电商-直播接口\n  desc: 来客电商直播接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.living\n  groupName: 直播\n  contactName: living\n  contactUrl: http://www.living.com/\n  contactEmail: 36309839@qq.com', 'e4b888bcf97333fc37ce8a662c73a86f', '2024-06-25 17:43:51', '2024-07-02 08:27:28', 'nacos', '222.244.188.112', '', '23467031-bda4-48a0-a7ab-6bc1a4be22fd', '', '', '', 'yaml', '', '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (9133, 'com.laiketui.app.api.services.VirtualService:1.0.0::provider:laike-app', 'dubbo', '{\"parameters\":{\"version\":\"1.0.0\",\"side\":\"provider\",\"interface\":\"com.laiketui.app.api.services.VirtualService\",\"pid\":\"21592\",\"application\":\"laike-app\",\"dubbo\":\"2.0.2\",\"release\":\"3.0.8\",\"anyhost\":\"true\",\"methods\":\"getWriteRecord\",\"deprecated\":\"false\",\"service-name-mapping\":\"true\",\"qos.enable\":\"false\",\"generic\":\"false\",\"bind.port\":\"20991\",\"revision\":\"1.0.0\",\"bind.ip\":\"192.168.1.11\",\"background\":\"false\",\"dynamic\":\"true\",\"qos.accept.foreign.ip\":\"false\",\"timestamp\":\"1745742468758\"},\"canonicalName\":\"com.laiketui.app.api.services.VirtualService\",\"codeSource\":\"file:/E:/work/mallcode/thinkinshop/laike-app-api/target/classes/\",\"methods\":[{\"name\":\"getWriteRecord\",\"parameterTypes\":[\"java.lang.Integer\"],\"returnType\":\"java.util.Map\\u003cjava.lang.String,java.lang.Object\\u003e\",\"annotations\":[]}],\"types\":[{\"type\":\"java.util.Map\\u003cjava.lang.String,java.lang.Object\\u003e\",\"items\":[\"java.lang.String\",\"java.lang.Object\"]},{\"type\":\"java.lang.Object\"},{\"type\":\"java.lang.String\"},{\"type\":\"java.lang.Integer\"}],\"annotations\":[]}', '54e5e666b850e946ad99b129ab5dce84', '2024-06-27 09:37:38', '2025-04-27 08:27:49', NULL, '192.168.1.11', '', '', NULL, NULL, NULL, 'text', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (9134, 'com.laiketui.app.api.services.VirtualService', 'mapping', 'laike-app', '2d2238fdf96955db8be663db827b1c23', '2024-06-27 09:37:38', '2024-06-27 09:37:38', NULL, '192.168.26.1', '', '', NULL, NULL, NULL, 'text', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (9842, 'laike-user-xlz.yml', 'DEFAULT_GROUP', 'server:\n  #配置成和tomcat端口一致（war部署）\n  port: ${tomcat_port:18022}\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    # 当部署到同一个tomcat中的webapp 里面的时候 context-path 需要修改成跟webapp中的文件名同名；\n    # 如果没有修改则默认取tomcat中的文件夹名称 作为contextpath的默认值\n    context-path: /user\n\n#http服务所在的内网/或外网节点ip\nnode:\n  ip: 0.0.0.0\n\n# Nacos 注册中心\n# dubbo:\n#   application:\n#     name: laike-user\n#     # 禁用QOS同一台机器可能会有端口冲突现象\n#     qos-enable: false\n#     qos-accept-foreign-ip: false\n#     # 配置注册中心\n#   registry:\n#     address: nacos://localhost:8848\n#   # 设置超时时间\n#   consumer:\n#     timeout: 6000\n#   protocol:\n#     name: dubbo\n#     port: ${NACOS_PORT:21889} \n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-user\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21889} \n\n#swagger 配置\nswagger:\n  title: 来客电商-用户接口\n  desc: 来客电商用户接口API\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.user\n  groupName: 用户\n  contactName: user\n  contactUrl: http://www.laiketui.com/\n  contactEmail:', 'ad08b13d1b15a34e06b4914c4cf5fd67', '2024-07-09 16:39:41', '2024-07-09 16:39:41', NULL, '113.246.104.193', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', NULL, NULL, NULL, 'yaml', NULL, '');
INSERT INTO `config_info` (`id`, `data_id`, `group_id`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `app_name`, `tenant_id`, `c_desc`, `c_use`, `effect`, `type`, `c_schema`, `encrypted_data_key`) VALUES (9843, 'laike-task-xlz.yml', 'DEFAULT_GROUP', 'server:\n  port: 18021\n  ssl:\n    enabled: false\n  tomcat:\n    uri-encoding: UTF-8\n  servlet:\n    context-path: /task\n    \n#dubbo:\n#  application:\n#    name: laike_app\n#  registry:\n#    id: zookeeper-registryapplication.yml\n#    protocol: zookeeper\n#    address: 127.0.0.1:2181\n#  protocol:\n#    name: dubbo\n#    port: 21898\n#    accesslog: dubbo-access.log\n#  provider:\n#    retries: 1 # 远程服务调用重试次数, 不包括第一次调用, 不需要重试请设为0\n#    timeout: 3000 # 远程服务调用超时时间(毫秒)\n#    delay: -1 # 延迟注册服务时间(毫秒)- , 设为-1时, 表示延迟到Spring容器初始化完成时暴露服务\n#    filter: -exception # 服务提供方远程调用过程拦截器名称, 多个名称用逗号分隔\n#  monitor:\n#    protocol: registry\n\n# Nacos 注册中心\ndubbo:\n  application:\n    name: laike-task\n    # 禁用QOS同一台机器可能会有端口冲突现象\n    qos-enable: false\n    qos-accept-foreign-ip: false\n    # 配置注册中心\n  registry:\n    address: nacos://localhost:8848\n    parameters: laike-dubbo-nacos\n  # 设置超时时间\n  consumer:\n    timeout: 6000\n  protocol:\n    name: dubbo\n    port: ${NACOS_PORT:21898}\n\n# logging:\n#   level:\n#     com:\n#       laiketui: info\n#   config: classpath:logback.xml\n\n#swagger 配置\nswagger:\n  title: 来客电商-任务调度\n  desc: 来客电商任务调度\n  version: 0.0.1.SNAPSHOT\n  termsOfServiceUrl: javascript:void(0)\n  license: Apache 2.0\n  licenseUrl: http://www.apache.org/licenses/LICENSE-2.0.html\n  basePackage: com.laiketui.task\n  groupName: 任务调度\n  contactName: task\n  contactUrl: http://www.laiketui.com/\n  contactEmail:\n#xxl-job\nxxl:\n  job:\n    accessToken:\n    admin:\n      addresses: http://127.0.0.1:3366/task # 任务调度中心部署根地址（必填）\n    executor:\n      appname: laike-task                   # 对应 执行管理器 AppName\n      ip: 127.0.0.1                         # 执行器ip，可以不填，会自动识别注册\n      logpath: ./task.log                   # 执行器运行日志文件存储磁盘路径\n      logretentiondays: 30                  # 执行器日志保存天数，值大于3时生效，启用执行器log文件定期清理功能，否则不生效。\n      port: 2024                           # 执行器端口号 \n      #AccessToken：执行器通讯token，非空时启用', 'b520cf6337d094f741c03899ac590f74', '2024-07-09 16:39:41', '2024-07-09 16:39:41', NULL, '113.246.104.193', '', 'f124b515-5b21-4bf8-9f72-25b585ee1343', NULL, NULL, NULL, 'yaml', NULL, '');
